K230_COMMON_SOURCE = 'import json\nimport os\n\n\nCALIB_FILE = "/sdcard/app/aiming_calib.json"\n\n\ndef _ensure_parent_dir(path):\n    parts = path.split("/")[:-1]\n    current = ""\n    for part in parts:\n        if not part:\n            current = "/"\n            continue\n        if current == "/":\n            current = "/" + part\n        else:\n            current = current + "/" + part\n        try:\n            os.stat(current)\n        except OSError:\n            try:\n                os.mkdir(current)\n            except OSError:\n                pass\n\n\ndef load_calibration(default_red, default_black, default_violet, default_bright=None):\n    try:\n        with open(CALIB_FILE, "r") as f:\n            data = json.load(f)\n        red = tuple(data.get("red_threshold", default_red))\n        black = tuple(data.get("black_threshold", default_black))\n        violet = tuple(data.get("violet_threshold", default_violet))\n        if default_bright is None:\n            bright = None\n        else:\n            bright = tuple(data.get("bright_threshold", default_bright))\n        return True, red, black, violet, bright\n    except Exception as e:\n        print("[Calib] load failed:", e)\n        return False, tuple(default_red), tuple(default_black), tuple(default_violet), default_bright\n\n\ndef save_calibration(red_threshold, black_threshold, violet_threshold, bright_threshold=None):\n    payload = {\n        "red_threshold": list(red_threshold),\n        "black_threshold": list(black_threshold),\n        "violet_threshold": list(violet_threshold),\n    }\n    if bright_threshold is not None:\n        payload["bright_threshold"] = list(bright_threshold)\n\n    try:\n        _ensure_parent_dir(CALIB_FILE)\n        with open(CALIB_FILE, "w") as f:\n            json.dump(payload, f)\n        print("[Calib] saved:", CALIB_FILE)\n        return True\n    except Exception as e:\n        print("[Calib] save failed:", e)\n        return False\n'
STAND_AIMING_SOURCE = 'from media.sensor import *\nfrom media.display import *\nfrom media.media import *\nimport gc\nimport math\nimport os\nimport sys\nimport time\nfrom machine import FPIOA, Pin, UART\n\n\nCAMERA_ID = 2\nFRAME_WIDTH = 400\nFRAME_HEIGHT = 300\nSENSOR_HMIRROR = True\nSENSOR_VFLIP = True\n\nUART_ID = 2\nTX_PIN = 5\nRX_PIN = 6\nUART_BAUDRATE = 115200\nSTART_BUTTON_BOARD_PIN = 28\nSTART_BUTTON_GPIO_NUM = 28\nBUTTON_DEBOUNCE_MS = 35\n\nRECT_THRESHOLD = 8000\nRECT_BINARY_THRESHOLD = (0, 72)\nTARGET_WIDTH_CM = 25.0\nTARGET_HEIGHT_CM = 29.7\nTARGET_ASPECT = TARGET_WIDTH_CM / TARGET_HEIGHT_CM\nTARGET_ASPECT_PENALTY_SCALE = 12000\nTARGET_MIN_W = 44\nTARGET_MIN_H = 44\nTARGET_MIN_AREA = 3600\nTARGET_CENTER_ALPHA = 0.90\nTARGET_RESET_DIST_PX = 144\nTARGET_STICKY_DIST_PX = 1\nTARGET_LEAD_GAIN = 0.12\nTARGET_LEAD_MAX_PX = 12\nTARGET_MAX_JUMP_PX = 96\nTARGET_MAX_SIZE_CHANGE_RATIO = 0.35\nTARGET_EDGE_MARGIN_PX = 4\nTARGET_EDGE_COMP_MIN_RATIO = 0.55\nTARGET_MIN_OVERLAP_RATIO = 0.18\nTARGET_INIT_CENTER_BIAS = 14\nTARGET_NEAR_CENTER_PX = 180\nTARGET_BORDER_SAMPLE_COUNT = 10\nTARGET_BORDER_HIT_RATIO_MIN = 0.32\nTARGET_BORDER_SCORE_SCALE = 9000\nTARGET_MAX_MISS_FRAMES = 6\nTARGET_DETECT_INTERVAL = 1\n\nALIGNED_TOLERANCE_PX = 6\n# Target point is constrained to the same vertical line as screen center.\n# Positive Z means the target point is below screen center; negative means above.\nTARGET_POINT_OFFSET_Z = -40\n\nDEBUG_MODE = True\nDEBUG_TEXT_OVERLAY = False\nFRAME_LOOP_DELAY_MS = 0\nGC_INTERVAL = 180\n\nSNAPSHOT_RETRY_COUNT = 3\nSNAPSHOT_RETRY_DELAY_MS = 3\nSENSOR_WARMUP_FRAMES = 2\nSTART_CAMERA_RETRY_COUNT = 2\nSTART_CAMERA_RETRY_DELAY_MS = 10\nSTART_CAMERA_SETTLE_MS = 28\nSTART_CAMERA_SETTLE_STEP_MS = 18\nALLOW_CHANNEL_FALLBACK = False\nMAX_CONSECUTIVE_SNAPSHOT_FAILURES = 5\n\nBUILD_TAG = "2026-07-14-rect-center-v1"\nCURRENT_SNAPSHOT_CHN = CAM_CHN_ID_1\n\n\ndef draw_text(img, x, y, text, color=(255, 255, 255), scale=1):\n    text = str(text)\n    if hasattr(img, "draw_string_advanced"):\n        img.draw_string_advanced(x, y, max(16, 16 * scale), text, color=color)\n    else:\n        img.draw_string(x, y, text, color=color, scale=scale)\n\n\ndef _pin_pull_up_value():\n    for name in ("PULL_UP", "PULLUP", "PULL_UP_ENABLE"):\n        value = getattr(Pin, name, None)\n        if value is not None:\n            return value\n    return None\n\n\ndef _map_board_pin_to_gpio(fpioa, board_pin, gpio_num):\n    if not hasattr(fpioa, "set_function"):\n        return\n    for func_name in (\n        "GPIO{}_FUNC".format(gpio_num),\n        "GPIO{}".format(gpio_num),\n        "GPIOHS{}".format(gpio_num),\n        "GPIOHS{}_FUNC".format(gpio_num),\n    ):\n        func = getattr(fpioa, func_name, None)\n        if func is not None:\n            fpioa.set_function(board_pin, func)\n            return\n\n\nclass StartButton:\n    def __init__(self, board_pin, gpio_num):\n        self.pin = None\n        self.ready = False\n        self.latched = False\n        self.last_raw_value = 1\n        self.stable_value = 1\n        self.last_change_ms = 0\n        self._init_pin(board_pin, gpio_num)\n\n    def _init_pin(self, board_pin, gpio_num):\n        try:\n            fpioa = FPIOA()\n            _map_board_pin_to_gpio(fpioa, board_pin, gpio_num)\n            pull_up = _pin_pull_up_value()\n            if pull_up is None:\n                try:\n                    self.pin = Pin(gpio_num, Pin.IN)\n                except Exception:\n                    self.pin = Pin(board_pin, Pin.IN)\n            else:\n                try:\n                    self.pin = Pin(gpio_num, Pin.IN, pull_up)\n                except Exception:\n                    self.pin = Pin(board_pin, Pin.IN, pull_up)\n            self.ready = self.pin is not None\n        except Exception as e:\n            print("[Key] start init failed:", e)\n            self.pin = None\n            self.ready = False\n\n    def poll_pressed(self):\n        if self.latched or self.pin is None:\n            return self.latched\n        now = time.ticks_ms()\n        try:\n            raw_value = self.pin.value()\n        except Exception:\n            return False\n        if raw_value != self.last_raw_value:\n            self.last_raw_value = raw_value\n            self.last_change_ms = now\n            return False\n        if time.ticks_diff(now, self.last_change_ms) < BUTTON_DEBOUNCE_MS:\n            return False\n        if raw_value != self.stable_value:\n            self.stable_value = raw_value\n            if self.stable_value == 0:\n                self.latched = True\n                return True\n        return False\n\n\ndef _snapshot_channel_name(snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return "chn1"\n    return "chn0"\n\n\ndef _configure_sensor_for_channel(sensor, snapshot_chn):\n    sensor.reset()\n    try:\n        sensor.set_hmirror(SENSOR_HMIRROR)\n    except Exception:\n        pass\n    try:\n        sensor.set_vflip(SENSOR_VFLIP)\n    except Exception:\n        pass\n    if snapshot_chn == CAM_CHN_ID_1:\n        sensor.set_framesize(Sensor.FHD)\n        sensor.set_pixformat(Sensor.YUV420SP)\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT, chn=CAM_CHN_ID_1)\n        sensor.set_pixformat(Sensor.RGB565, chn=CAM_CHN_ID_1)\n    else:\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT)\n        sensor.set_pixformat(Sensor.RGB565)\n\n\ndef _snapshot_once(sensor, snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return sensor.snapshot(chn=CAM_CHN_ID_1)\n    return sensor.snapshot(chn=CAM_CHN_ID_0)\n\n\ndef init_camera_sensor(camera_id=None):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    try:\n        sensor = Sensor(id=camera_id)\n    except OSError as e:\n        if "already inited" not in str(e):\n            raise\n        Sensor.deinit()\n        time.sleep_ms(20)\n        sensor = Sensor(id=camera_id)\n    return sensor\n\n\ndef _start_camera_on_channel(sensor, camera_id, snapshot_chn):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    for attempt in range(START_CAMERA_RETRY_COUNT):\n        os.exitpoint()\n        try:\n            MediaManager.init()\n            sensor.run()\n            settle_ms = START_CAMERA_SETTLE_MS + attempt * START_CAMERA_SETTLE_STEP_MS\n            time.sleep_ms(settle_ms)\n            for _ in range(SENSOR_WARMUP_FRAMES):\n                os.exitpoint()\n                try:\n                    _snapshot_once(sensor, snapshot_chn)\n                    return True\n                except Exception as e:\n                    last_error = e\n                    time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n            last_error = RuntimeError(\n                "camera id {} no warmup frames on {}".format(\n                    camera_id, _snapshot_channel_name(snapshot_chn)\n                )\n            )\n        except Exception as e:\n            last_error = e\n\n        try:\n            sensor.stop()\n        except Exception:\n            pass\n        try:\n            MediaManager.deinit()\n        except Exception:\n            pass\n        try:\n            _configure_sensor_for_channel(sensor, snapshot_chn)\n        except Exception:\n            pass\n        gc.collect()\n        time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n\n    raise last_error\n\n\ndef start_camera(sensor, camera_id=None):\n    global CURRENT_SNAPSHOT_CHN\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    channels = (CAM_CHN_ID_1,)\n    if ALLOW_CHANNEL_FALLBACK:\n        channels = (CAM_CHN_ID_1, CAM_CHN_ID_0)\n    for snapshot_chn in channels:\n        os.exitpoint()\n        try:\n            _configure_sensor_for_channel(sensor, snapshot_chn)\n            _start_camera_on_channel(sensor, camera_id, snapshot_chn)\n            CURRENT_SNAPSHOT_CHN = snapshot_chn\n            return True\n        except Exception as e:\n            last_error = e\n            try:\n                sensor.stop()\n            except Exception:\n                pass\n            try:\n                MediaManager.deinit()\n            except Exception:\n                pass\n            gc.collect()\n            time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef snapshot_with_retry(sensor):\n    last_error = None\n    for _ in range(SNAPSHOT_RETRY_COUNT):\n        os.exitpoint()\n        try:\n            return _snapshot_once(sensor, CURRENT_SNAPSHOT_CHN)\n        except RuntimeError as e:\n            last_error = e\n            time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef init_preview_display():\n    try:\n        Display.init(\n            Display.VIRT, width=FRAME_WIDTH, height=FRAME_HEIGHT, fps=100, to_ide=True\n        )\n        print("[Display] VIRT preview")\n    except Exception as e:\n        print("[Display] VIRT failed:", e)\n        Display.init(Display.ST7701, to_ide=True)\n        print("[Display] ST7701 preview")\n\n\ndef restart_camera(sensor):\n    os.exitpoint()\n    print("[Sensor] restarting...")\n    try:\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n    except Exception:\n        pass\n    try:\n        MediaManager.deinit()\n    except Exception:\n        pass\n    try:\n        Sensor.deinit()\n    except Exception:\n        pass\n    gc.collect()\n    time.sleep_ms(20)\n    sensor = init_camera_sensor()\n    start_camera(sensor)\n    print("[Sensor] restart done")\n    return sensor\n\n\nclass RectTracker:\n    def __init__(self):\n        self.frame_id = 0\n        self.target_rect = None\n        self.target_center = None\n        self.target_found = False\n        self.target_miss_count = 0\n        self.last_target_rect = None\n        self.last_target_center = None\n\n    def _distance_sq(self, p0, p1):\n        dx = p0[0] - p1[0]\n        dy = p0[1] - p1[1]\n        return dx * dx + dy * dy\n\n    def _clamp_rect(self, x, y, w, h):\n        x = max(0, min(FRAME_WIDTH - 1, int(x)))\n        y = max(0, min(FRAME_HEIGHT - 1, int(y)))\n        w = max(1, min(FRAME_WIDTH - x, int(w)))\n        h = max(1, min(FRAME_HEIGHT - y, int(h)))\n        return (x, y, w, h)\n\n    def _clamp_point(self, point):\n        return (\n            max(0, min(FRAME_WIDTH - 1, int(point[0]))),\n            max(0, min(FRAME_HEIGHT - 1, int(point[1]))),\n        )\n\n    def _smooth_center(self, current, last_center, alpha, reset_px, sticky_px):\n        if last_center is None:\n            return current\n        dist_sq = self._distance_sq(current, last_center)\n        if dist_sq <= (sticky_px * sticky_px):\n            return last_center\n        if dist_sq > (reset_px * reset_px):\n            return current\n        return (\n            int(last_center[0] * (1 - alpha) + current[0] * alpha),\n            int(last_center[1] * (1 - alpha) + current[1] * alpha),\n        )\n\n    def _apply_motion_lead(self, current, last_center, gain, max_px):\n        if current is None or last_center is None or gain <= 0:\n            return current\n        dx = current[0] - last_center[0]\n        dy = current[1] - last_center[1]\n        lead_x = int(dx * gain)\n        lead_y = int(dy * gain)\n        if lead_x > max_px:\n            lead_x = max_px\n        elif lead_x < -max_px:\n            lead_x = -max_px\n        if lead_y > max_px:\n            lead_y = max_px\n        elif lead_y < -max_px:\n            lead_y = -max_px\n        return self._clamp_point((current[0] + lead_x, current[1] + lead_y))\n\n    def _rect_aspect_error(self, w, h):\n        aspect = w / max(h, 1)\n        target_inv = 1.0 / TARGET_ASPECT\n        return min(abs(aspect - TARGET_ASPECT), abs(aspect - target_inv))\n\n    def _rect_center_from_corners(self, corners):\n        sx = 0\n        sy = 0\n        points = []\n        for p in corners:\n            sx += p[0]\n            sy += p[1]\n            points.append((p[0], p[1]))\n        avg_center = (sx / 4, sy / 4)\n\n        points.sort(key=lambda p: math.atan2(p[1] - avg_center[1], p[0] - avg_center[0]))\n        p0 = points[0]\n        p1 = points[1]\n        p2 = points[2]\n        p3 = points[3]\n\n        x1 = p0[0]\n        y1 = p0[1]\n        x2 = p2[0]\n        y2 = p2[1]\n        x3 = p1[0]\n        y3 = p1[1]\n        x4 = p3[0]\n        y4 = p3[1]\n\n        denom = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4)\n        if abs(denom) < 1:\n            return self._clamp_point(avg_center)\n\n        det1 = x1 * y2 - y1 * x2\n        det2 = x3 * y4 - y3 * x4\n        center_x = (det1 * (x3 - x4) - (x1 - x2) * det2) / denom\n        center_y = (det1 * (y3 - y4) - (y1 - y2) * det2) / denom\n        if center_x < -8 or center_x > (FRAME_WIDTH + 8) or center_y < -8 or center_y > (FRAME_HEIGHT + 8):\n            return self._clamp_point(avg_center)\n        return self._clamp_point((center_x, center_y))\n\n    def _rect_size_change_ok(self, rect, last_rect):\n        if last_rect is None:\n            return True\n        _, _, w, h = rect\n        _, _, last_w, last_h = last_rect\n        if last_w <= 0 or last_h <= 0:\n            return True\n        dw = abs(w - last_w) / last_w\n        dh = abs(h - last_h) / last_h\n        return dw <= TARGET_MAX_SIZE_CHANGE_RATIO and dh <= TARGET_MAX_SIZE_CHANGE_RATIO\n\n    def _compensate_edge_rect(self, rect, last_rect):\n        if last_rect is None:\n            return rect\n        x, y, w, h = rect\n        _, _, last_w, last_h = last_rect\n        if last_w <= 0 or last_h <= 0:\n            return rect\n\n        x2 = x + w\n        y2 = y + h\n        if x <= TARGET_EDGE_MARGIN_PX and w < int(last_w * TARGET_EDGE_COMP_MIN_RATIO):\n            w = last_w\n        elif x2 >= (FRAME_WIDTH - TARGET_EDGE_MARGIN_PX) and w < int(last_w * TARGET_EDGE_COMP_MIN_RATIO):\n            x = max(0, x2 - last_w)\n            w = FRAME_WIDTH - x if x + last_w > FRAME_WIDTH else last_w\n\n        if y <= TARGET_EDGE_MARGIN_PX and h < int(last_h * TARGET_EDGE_COMP_MIN_RATIO):\n            h = last_h\n        elif y2 >= (FRAME_HEIGHT - TARGET_EDGE_MARGIN_PX) and h < int(last_h * TARGET_EDGE_COMP_MIN_RATIO):\n            y = max(0, y2 - last_h)\n            h = FRAME_HEIGHT - y if y + last_h > FRAME_HEIGHT else last_h\n\n        return self._clamp_rect(x, y, w, h)\n\n    def _rect_overlap_ratio(self, rect_a, rect_b):\n        if rect_a is None or rect_b is None:\n            return 0.0\n        ax, ay, aw, ah = rect_a\n        bx, by, bw, bh = rect_b\n        ax2 = ax + aw\n        ay2 = ay + ah\n        bx2 = bx + bw\n        by2 = by + bh\n        ix1 = max(ax, bx)\n        iy1 = max(ay, by)\n        ix2 = min(ax2, bx2)\n        iy2 = min(ay2, by2)\n        iw = ix2 - ix1\n        ih = iy2 - iy1\n        if iw <= 0 or ih <= 0:\n            return 0.0\n        inter = iw * ih\n        min_area = min(max(1, aw * ah), max(1, bw * bh))\n        return inter / min_area\n\n    def _rect_border_hit_ratio(self, rect_img, rect):\n        x, y, w, h = rect\n        if w <= 4 or h <= 4:\n            return 0.0\n        inset = max(1, min(6, min(w, h) // 12))\n        x1 = x + inset\n        y1 = y + inset\n        x2 = x + w - 1 - inset\n        y2 = y + h - 1 - inset\n        if x2 <= x1 or y2 <= y1:\n            return 0.0\n\n        hits = 0\n        total = 0\n        steps = max(4, TARGET_BORDER_SAMPLE_COUNT)\n        for idx in range(steps):\n            t = idx / max(1, steps - 1)\n            sx = int(x1 + (x2 - x1) * t)\n            sy = int(y1 + (y2 - y1) * t)\n            points = ((sx, y1), (sx, y2), (x1, sy), (x2, sy))\n            for px, py in points:\n                total += 1\n                try:\n                    if rect_img.get_pixel(px, py):\n                        hits += 1\n                except Exception:\n                    pass\n        if total <= 0:\n            return 0.0\n        return hits / total\n\n    def _accept_center(self, candidate_center, last_center):\n        if candidate_center is None or last_center is None:\n            return True\n        return self._distance_sq(candidate_center, last_center) <= (TARGET_MAX_JUMP_PX * TARGET_MAX_JUMP_PX)\n\n    def _prepare_rect_image(self, img):\n        rect_img = img.to_grayscale()\n        rect_img.binary([RECT_BINARY_THRESHOLD])\n        return rect_img\n\n    def _select_best_rect(self, rect_img, rects, reference_center, reference_rect):\n        best = None\n        best_score = None\n        image_center = (FRAME_WIDTH // 2, FRAME_HEIGHT // 2)\n\n        for r in rects:\n            raw_rect = r.rect()\n            corners = r.corners()\n            if raw_rect is None or corners is None or len(corners) != 4:\n                continue\n\n            rect = self._compensate_edge_rect(raw_rect, reference_rect)\n            x, y, w, h = rect\n            if w < TARGET_MIN_W or h < TARGET_MIN_H:\n                continue\n            area = w * h\n            if area < TARGET_MIN_AREA:\n                continue\n            if not self._rect_size_change_ok(rect, reference_rect):\n                continue\n\n            center = self._rect_center_from_corners(corners)\n            border_hit_ratio = self._rect_border_hit_ratio(rect_img, rect)\n            if border_hit_ratio < TARGET_BORDER_HIT_RATIO_MIN:\n                continue\n            if reference_center is not None:\n                jump_sq = self._distance_sq(center, reference_center)\n                if jump_sq > (TARGET_RESET_DIST_PX * TARGET_RESET_DIST_PX):\n                    continue\n            if reference_rect is not None:\n                overlap_ratio = self._rect_overlap_ratio(rect, reference_rect)\n                if overlap_ratio < TARGET_MIN_OVERLAP_RATIO and (\n                    reference_center is None\n                    or self._distance_sq(center, reference_center) > (TARGET_STICKY_DIST_PX * TARGET_STICKY_DIST_PX)\n                ):\n                    continue\n\n            aspect_penalty = int(self._rect_aspect_error(w, h) * TARGET_ASPECT_PENALTY_SCALE)\n            if reference_center is not None:\n                distance_penalty = self._distance_sq(center, reference_center) // 10\n            else:\n                distance_penalty = self._distance_sq(center, image_center) // TARGET_INIT_CENTER_BIAS\n            edge_penalty = 0\n            if x <= 2 or y <= 2 or (x + w) >= (FRAME_WIDTH - 2) or (y + h) >= (FRAME_HEIGHT - 2):\n                edge_penalty = 3600\n            center_bias_bonus = 0\n            if self._distance_sq(center, image_center) <= (TARGET_NEAR_CENTER_PX * TARGET_NEAR_CENTER_PX):\n                center_bias_bonus = 2000\n            border_score_bonus = int(border_hit_ratio * TARGET_BORDER_SCORE_SCALE)\n\n            score = area - aspect_penalty - distance_penalty - edge_penalty + center_bias_bonus + border_score_bonus\n            if best_score is None or score > best_score:\n                best_score = score\n                best = (rect, center)\n\n        return best\n\n    def detect(self, img):\n        self.frame_id += 1\n        if self.target_found and (self.frame_id % TARGET_DETECT_INTERVAL) != 0:\n            return self.target_found, self.target_rect, self.target_center\n\n        previous_rect = self.last_target_rect\n        previous_center = self.last_target_center\n        self.target_rect = None\n        self.target_center = None\n        self.target_found = False\n\n        rect_img = self._prepare_rect_image(img)\n        rects = rect_img.find_rects(threshold=RECT_THRESHOLD) or []\n        chosen = self._select_best_rect(rect_img, rects, previous_center, previous_rect)\n        if chosen is not None:\n            _, center = chosen\n            if not self._accept_center(center, previous_center):\n                chosen = None\n\n        if chosen is None:\n            self.target_miss_count += 1\n            if previous_rect and previous_center and self.target_miss_count <= TARGET_MAX_MISS_FRAMES:\n                self.target_rect = previous_rect\n                self.target_center = previous_center\n                self.target_found = True\n            else:\n                self.last_target_rect = None\n                self.last_target_center = None\n            return self.target_found, self.target_rect, self.target_center\n\n        self.target_miss_count = 0\n        rect, center = chosen\n        self.target_rect = rect\n        self.target_center = self._smooth_center(\n            center,\n            previous_center,\n            TARGET_CENTER_ALPHA,\n            TARGET_RESET_DIST_PX,\n            TARGET_STICKY_DIST_PX,\n        )\n        self.target_center = self._apply_motion_lead(\n            self.target_center,\n            previous_center,\n            TARGET_LEAD_GAIN,\n            TARGET_LEAD_MAX_PX,\n        )\n        self.target_found = True\n        self.last_target_rect = self.target_rect\n        self.last_target_center = self.target_center\n        return self.target_found, self.target_rect, self.target_center\n\n\nclass RectCenterSystem:\n    def __init__(self):\n        self.tracker = RectTracker()\n        self.uart = None\n        self.comm_started = False\n        self.start_button = StartButton(START_BUTTON_BOARD_PIN, START_BUTTON_GPIO_NUM)\n        self.frame_count = 0\n        self.fps = 0.0\n        self.last_fps_time = time.ticks_ms()\n        self.gc_counter = 0\n        self.last_aligned = False\n        self._aligned_latched = False\n\n    def init_uart(self):\n        try:\n            fpioa = FPIOA()\n            fpioa.set_function(TX_PIN, fpioa.UART2_TXD)\n            fpioa.set_function(RX_PIN, fpioa.UART2_RXD)\n            self.uart = UART(UART_ID, baudrate=UART_BAUDRATE)\n            print("[UART] init ok:", UART_BAUDRATE)\n            return True\n        except Exception as e:\n            print("[UART] init failed:", e)\n            return False\n\n    def send_status(self, status):\n        if self.uart and self.comm_started:\n            self.uart.write("STS,{}\\n".format(status))\n\n    def send_search(self):\n        if self.uart and self.comm_started:\n            self.uart.write("RECT,SEARCH\\n")\n\n    def send_offset(self, dx, dy):\n        if self.uart and self.comm_started:\n            self.uart.write("RECT,{},{},{}\\n".format(dx, dy, 1 if self.last_aligned else 0))\n\n    def send_aligned(self):\n        if self.uart and self.comm_started:\n            self.uart.write("RECT_OK\\n")\n\n    def _update_start_button(self):\n        if self.comm_started:\n            return\n        if self.start_button.poll_pressed():\n            self.comm_started = True\n            print("[Comm] start button pressed, UART enabled")\n            self.send_status("RECT_CENTER_READY")\n\n    def process_frame(self, img):\n        self.frame_count += 1\n        self.gc_counter += 1\n        self._update_start_button()\n\n        found, rect, center = self.tracker.detect(img)\n        screen_center = (FRAME_WIDTH // 2, FRAME_HEIGHT // 2)\n        target_point = (screen_center[0], screen_center[1] + TARGET_POINT_OFFSET_Z)\n\n        if not found or rect is None or center is None:\n            self.last_aligned = False\n            self._aligned_latched = False\n            self.send_search()\n            if DEBUG_MODE:\n                self._draw_overlay(img, None, None, screen_center, target_point, False)\n            return img\n\n        dx = center[0] - target_point[0]\n        dy = center[1] - target_point[1]\n        aligned = abs(dx) <= ALIGNED_TOLERANCE_PX and abs(dy) <= ALIGNED_TOLERANCE_PX\n        self.last_aligned = aligned\n        self.send_offset(dx, dy)\n        if aligned and not self._aligned_latched:\n            self.send_aligned()\n        self._aligned_latched = aligned\n\n        if DEBUG_MODE:\n            self._draw_overlay(img, rect, center, screen_center, target_point, aligned)\n        return img\n\n    def _draw_overlay(self, img, rect, center, screen_center, target_point, aligned):\n        scx, scy = screen_center\n        tx, ty = target_point\n        img.draw_cross(scx, scy, color=(120, 120, 120), size=8, thickness=1)\n        img.draw_line(scx, 0, scx, FRAME_HEIGHT - 1, color=(80, 80, 80), thickness=1)\n        img.draw_cross(tx, ty, color=(255, 255, 0), size=10, thickness=2)\n        img.draw_circle(tx, ty, ALIGNED_TOLERANCE_PX, color=(255, 255, 0), thickness=1)\n\n        if rect is not None:\n            x, y, w, h = rect\n            color = (0, 255, 0) if aligned else (0, 180, 255)\n            img.draw_rectangle(x, y, w, h, color=color, thickness=2)\n        if center is not None:\n            cx, cy = center\n            color = (0, 255, 0) if aligned else (255, 0, 0)\n            img.draw_cross(cx, cy, color=color, size=8, thickness=2)\n            img.draw_line(cx, cy, tx, ty, color=(255, 255, 255), thickness=1)\n\n        if DEBUG_TEXT_OVERLAY and center is not None:\n            draw_text(img, 4, 4, "dx={} dy={}".format(center[0] - tx, center[1] - ty))\n            draw_text(img, 4, 22, "fps={:.1f}".format(self.fps))\n            draw_text(img, 4, 40, "aligned={}".format(1 if aligned else 0))\n            draw_text(img, 4, 58, "z={}".format(TARGET_POINT_OFFSET_Z))\n        if not self.comm_started:\n            draw_text(img, 4, FRAME_HEIGHT - 18, "PRESS GPIO28 TO START UART", color=(255, 255, 0), scale=1)\n\n    def update_fps(self):\n        current_time = time.ticks_ms()\n        dt = time.ticks_diff(current_time, self.last_fps_time)\n        if dt >= 1000:\n            self.fps = self.frame_count * 1000 / dt\n            self.frame_count = 0\n            self.last_fps_time = current_time\n\n    def maybe_collect_gc(self):\n        if self.gc_counter >= GC_INTERVAL:\n            gc.collect()\n            self.gc_counter = 0\n\n\ndef main():\n    print("=" * 50)\n    print("K230 Rect Center Mode")\n    print("build:", BUILD_TAG)\n    print("fast mode enabled")\n    print("=" * 50)\n\n    system = RectCenterSystem()\n    system.init_uart()\n\n    print("[Display] init...")\n    init_preview_display()\n    try:\n        print("[Sensor] init...")\n        sensor = init_camera_sensor()\n        start_camera(sensor)\n    except Exception as e:\n        print("[Sensor] start failed, retry by restart:", e)\n        sensor = restart_camera(None)\n\n    print("[System] ready")\n\n    consecutive_snapshot_failures = 0\n    try:\n        while True:\n            os.exitpoint()\n            try:\n                img = snapshot_with_retry(sensor)\n                consecutive_snapshot_failures = 0\n            except RuntimeError as e:\n                consecutive_snapshot_failures += 1\n                if consecutive_snapshot_failures >= MAX_CONSECUTIVE_SNAPSHOT_FAILURES:\n                    print("[Sensor] snapshot failed repeatedly, restart:", e)\n                    sensor = restart_camera(sensor)\n                    consecutive_snapshot_failures = 0\n                time.sleep_ms(FRAME_LOOP_DELAY_MS)\n                continue\n\n            img = system.process_frame(img)\n            system.update_fps()\n            Display.show_image(img)\n            system.maybe_collect_gc()\n            time.sleep_ms(FRAME_LOOP_DELAY_MS)\n    except KeyboardInterrupt:\n        print("\\n[System] interrupted")\n    except Exception as e:\n        print("[Error]", e)\n        sys.print_exception(e)\n    finally:\n        print("[System] cleanup...")\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n        Display.deinit()\n        os.exitpoint(os.EXITPOINT_ENABLE_SLEEP)\n        time.sleep_ms(100)\n        MediaManager.deinit()\n        Sensor.deinit()\n        if system.uart:\n            system.uart.deinit()\n        print("[System] stopped")\n\n\nif __name__ == "__main__":\n    main()\n'
MOVE_AIMING_SOURCE = 'from media.sensor import *\nfrom media.display import *\nfrom media.media import *\nimport gc\nimport math\nimport os\nimport sys\nimport time\nfrom machine import FPIOA, Pin, UART\n\ntry:\n    from k230_common import load_calibration\nexcept ImportError:\n    def load_calibration(default_red, default_black, default_violet, default_bright=None):\n        return (\n            False,\n            tuple(default_red),\n            tuple(default_black),\n            tuple(default_violet),\n            default_bright,\n        )\n\n\nCAMERA_ID = 2\nFRAME_WIDTH = 400\nFRAME_HEIGHT = 300\nSENSOR_HMIRROR = True\nSENSOR_VFLIP = True\nTARGET_DETECT_INTERVAL = 1\nBULLSEYE_DETECT_INTERVAL = 1\nGC_INTERVAL = 180\n\nTARGET_WIDTH_CM = 25.0\nTARGET_HEIGHT_CM = 29.7\nCIRCLE_RADIUS_CM = 6.0\nTARGET_OUTER_DIAMETER_CM = 21.0\n\nRED_THRESHOLD = (41, 100, -28, 6, -14, 14)\nBLACK_THRESHOLD = (22, 69, -23, -3, -22, 16)\nVIOLET_THRESHOLD = (92, 100, -15, 6, -9, 11)\n\nRECT_THRESHOLD = 8000\nRECT_BINARY_THRESHOLD = (0, 72)\nTARGET_MIN_W = 44\nTARGET_MIN_H = 44\nTARGET_MIN_AREA = 3600\nTARGET_ASPECT = TARGET_WIDTH_CM / TARGET_HEIGHT_CM\nTARGET_ASPECT_PENALTY_SCALE = 12000\nTARGET_CENTER_ALPHA = 0.90\nTARGET_RESET_DIST_PX = 144\nTARGET_STICKY_DIST_PX = 1\nTARGET_LEAD_GAIN = 0.12\nTARGET_LEAD_MAX_PX = 12\nTARGET_MAX_JUMP_PX = 96\nTARGET_MAX_SIZE_CHANGE_RATIO = 0.35\nTARGET_EDGE_MARGIN_PX = 4\nTARGET_EDGE_COMP_MIN_RATIO = 0.55\nTARGET_MIN_OVERLAP_RATIO = 0.18\nTARGET_INIT_CENTER_BIAS = 14\nTARGET_NEAR_CENTER_PX = 180\nTARGET_BORDER_SAMPLE_COUNT = 10\nTARGET_BORDER_HIT_RATIO_MIN = 0.32\nTARGET_BORDER_SCORE_SCALE = 9000\nBULLSEYE_ROI_RATIO = 0.42\nBULLSEYE_GATE_RATIO = 0.60\nBULLSEYE_BLEND_ALPHA = 0.65\nBULLSEYE_CENTER_ALPHA = 0.84\nBULLSEYE_LEAD_GAIN = 0.18\nBULLSEYE_LEAD_MAX_PX = 10\n\nUART_BAUDRATE = 115200\nSTART_BUTTON_BOARD_PIN = 28\nSTART_BUTTON_GPIO_NUM = 28\nBUTTON_DEBOUNCE_MS = 35\nDEBUG_MODE = True\nDEBUG_TEXT_OVERLAY = False\nDISPLAY_FPS = 30\nFRAME_LOOP_DELAY_MS = 0\nSNAPSHOT_RETRY_COUNT = 3\nSNAPSHOT_RETRY_DELAY_MS = 3\nSENSOR_WARMUP_FRAMES = 2\nSTART_CAMERA_RETRY_COUNT = 2\nSTART_CAMERA_RETRY_DELAY_MS = 10\nSTART_CAMERA_SETTLE_MS = 28\nSTART_CAMERA_SETTLE_STEP_MS = 18\nALLOW_CHANNEL_FALLBACK = False\nMAX_CONSECUTIVE_SNAPSHOT_FAILURES = 5\nTARGET_MAX_MISS_FRAMES = 6\nLASER_MAX_MISS_FRAMES = 2\nLASER_STICKY_PX = 2\nPREDICT_TRACK_MAX_FRAMES = 30\nLASER_PREDICT_ROI_MARGIN_PX = 24\nCIRCLE_RADIUS_SMOOTHING_ALPHA = 0.45\nTARGET_POINT_HISTORY_LEN = 3\nLASER_POINT_HISTORY_LEN = 1\nRADIUS_HISTORY_LEN = 3\nBUILD_TAG = "2026-07-14-aim-fastboot-v19"\nCURRENT_SNAPSHOT_CHN = CAM_CHN_ID_1\n\n\ndef apply_calibration():\n    global RED_THRESHOLD, BLACK_THRESHOLD, VIOLET_THRESHOLD\n    ok, red, black, violet, _ = load_calibration(\n        RED_THRESHOLD, BLACK_THRESHOLD, VIOLET_THRESHOLD\n    )\n    RED_THRESHOLD = red\n    BLACK_THRESHOLD = black\n    VIOLET_THRESHOLD = violet\n    if ok:\n        print("[Calib] thresholds applied")\n    else:\n        print("[Calib] using built-in thresholds")\n\n\ndef _snapshot_channel_name(snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return "chn1"\n    return "chn0"\n\n\ndef _configure_sensor_for_channel(sensor, camera_id, snapshot_chn):\n    sensor.reset()\n    try:\n        sensor.set_hmirror(SENSOR_HMIRROR)\n    except Exception:\n        pass\n    try:\n        sensor.set_vflip(SENSOR_VFLIP)\n    except Exception:\n        pass\n    if snapshot_chn == CAM_CHN_ID_1:\n        sensor.set_framesize(Sensor.FHD)\n        sensor.set_pixformat(Sensor.YUV420SP)\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT, chn=CAM_CHN_ID_1)\n        sensor.set_pixformat(Sensor.RGB565, chn=CAM_CHN_ID_1)\n    else:\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT)\n        sensor.set_pixformat(Sensor.RGB565)\n\n\ndef _snapshot_once(sensor, snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return sensor.snapshot(chn=CAM_CHN_ID_1)\n    return sensor.snapshot(chn=CAM_CHN_ID_0)\n\n\ndef init_camera_sensor(camera_id=None):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    try:\n        sensor = Sensor(id=camera_id)\n    except OSError as e:\n        if "already inited" not in str(e):\n            raise\n        Sensor.deinit()\n        time.sleep_ms(20)\n        sensor = Sensor(id=camera_id)\n    return sensor\n\n\ndef _start_camera_on_channel(sensor, camera_id, snapshot_chn):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    for attempt in range(START_CAMERA_RETRY_COUNT):\n        os.exitpoint()\n        try:\n            MediaManager.init()\n            sensor.run()\n            settle_ms = START_CAMERA_SETTLE_MS + attempt * START_CAMERA_SETTLE_STEP_MS\n            time.sleep_ms(settle_ms)\n            for _ in range(SENSOR_WARMUP_FRAMES):\n                os.exitpoint()\n                try:\n                    _snapshot_once(sensor, snapshot_chn)\n                    return True\n                except Exception as e:\n                    last_error = e\n                    time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n            last_error = RuntimeError(\n                "camera id {} no warmup frames on {}".format(\n                    camera_id, _snapshot_channel_name(snapshot_chn)\n                )\n            )\n        except Exception as e:\n            last_error = e\n\n        try:\n            sensor.stop()\n        except Exception:\n            pass\n        try:\n            MediaManager.deinit()\n        except Exception:\n            pass\n        try:\n            _configure_sensor_for_channel(sensor, camera_id, snapshot_chn)\n        except Exception:\n            pass\n        gc.collect()\n        time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n\n    raise last_error\n\n\ndef start_camera(sensor, camera_id=None):\n    global CURRENT_SNAPSHOT_CHN\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    channels = (CAM_CHN_ID_1,)\n    if ALLOW_CHANNEL_FALLBACK:\n        channels = (CAM_CHN_ID_1, CAM_CHN_ID_0)\n    for snapshot_chn in channels:\n        os.exitpoint()\n        try:\n            _configure_sensor_for_channel(sensor, camera_id, snapshot_chn)\n            _start_camera_on_channel(sensor, camera_id, snapshot_chn)\n            CURRENT_SNAPSHOT_CHN = snapshot_chn\n            return True\n        except Exception as e:\n            last_error = e\n            try:\n                sensor.stop()\n            except Exception:\n                pass\n            try:\n                MediaManager.deinit()\n            except Exception:\n                pass\n            gc.collect()\n            time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef snapshot_with_retry(sensor):\n    last_error = None\n    for _ in range(SNAPSHOT_RETRY_COUNT):\n        os.exitpoint()\n        try:\n            return _snapshot_once(sensor, CURRENT_SNAPSHOT_CHN)\n        except RuntimeError as e:\n            last_error = e\n            time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef draw_text(img, x, y, text, color=(255, 255, 255), scale=1):\n    text = str(text)\n    if hasattr(img, "draw_string_advanced"):\n        img.draw_string_advanced(x, y, max(16, 16 * scale), text, color=color)\n    else:\n        img.draw_string(x, y, text, color=color, scale=scale)\n\n\ndef _pin_pull_up_value():\n    for name in ("PULL_UP", "PULLUP", "PULL_UP_ENABLE"):\n        value = getattr(Pin, name, None)\n        if value is not None:\n            return value\n    return None\n\n\ndef _map_board_pin_to_gpio(fpioa, board_pin, gpio_num):\n    if not hasattr(fpioa, "set_function"):\n        return\n    for func_name in (\n        "GPIO{}_FUNC".format(gpio_num),\n        "GPIO{}".format(gpio_num),\n        "GPIOHS{}".format(gpio_num),\n        "GPIOHS{}_FUNC".format(gpio_num),\n    ):\n        func = getattr(fpioa, func_name, None)\n        if func is not None:\n            fpioa.set_function(board_pin, func)\n            return\n\n\nclass StartButton:\n    def __init__(self, board_pin, gpio_num):\n        self.pin = None\n        self.ready = False\n        self.latched = False\n        self.last_raw_value = 1\n        self.stable_value = 1\n        self.last_change_ms = 0\n        self._init_pin(board_pin, gpio_num)\n\n    def _init_pin(self, board_pin, gpio_num):\n        try:\n            fpioa = FPIOA()\n            _map_board_pin_to_gpio(fpioa, board_pin, gpio_num)\n            pull_up = _pin_pull_up_value()\n            if pull_up is None:\n                try:\n                    self.pin = Pin(gpio_num, Pin.IN)\n                except Exception:\n                    self.pin = Pin(board_pin, Pin.IN)\n            else:\n                try:\n                    self.pin = Pin(gpio_num, Pin.IN, pull_up)\n                except Exception:\n                    self.pin = Pin(board_pin, Pin.IN, pull_up)\n            self.ready = self.pin is not None\n        except Exception as e:\n            print("[Key] start init failed:", e)\n            self.pin = None\n            self.ready = False\n\n    def poll_pressed(self):\n        if self.latched or self.pin is None:\n            return self.latched\n        now = time.ticks_ms()\n        try:\n            raw_value = self.pin.value()\n        except Exception:\n            return False\n        if raw_value != self.last_raw_value:\n            self.last_raw_value = raw_value\n            self.last_change_ms = now\n            return False\n        if time.ticks_diff(now, self.last_change_ms) < BUTTON_DEBOUNCE_MS:\n            return False\n        if raw_value != self.stable_value:\n            self.stable_value = raw_value\n            if self.stable_value == 0:\n                self.latched = True\n                return True\n        return False\n\n\ndef init_preview_display():\n    try:\n        Display.init(\n            Display.VIRT, width=FRAME_WIDTH, height=FRAME_HEIGHT, fps=100, to_ide=True\n        )\n        print("[Display] VIRT preview")\n    except Exception as e:\n        print(f"[Display] VIRT failed: {e}")\n        Display.init(Display.ST7701, to_ide=True)\n        print("[Display] ST7701 preview")\n\n\ndef restart_camera(sensor):\n    os.exitpoint()\n    print("[Sensor] restarting...")\n    try:\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n    except Exception:\n        pass\n    try:\n        MediaManager.deinit()\n    except Exception:\n        pass\n    try:\n        Sensor.deinit()\n    except Exception:\n        pass\n    gc.collect()\n    time.sleep_ms(20)\n    sensor = init_camera_sensor()\n    start_camera(sensor)\n    print("[Sensor] restart done")\n    return sensor\n\n\nclass TargetDetector:\n    def __init__(self):\n        self.target_rect = None\n        self.target_center = None\n        self.target_diameter_px = 0\n        self.bullseye_center = None\n        self.laser_spot = None\n        self.target_found = False\n        self.bullseye_found = False\n        self.laser_found = False\n        self.pixel_to_cm_ratio_x = 0.0\n        self.pixel_to_cm_ratio_y = 0.0\n        self.target_plane_corners_cm = None\n        self.target_to_image_h = None\n        self.image_to_target_h = None\n        self.bullseye_plane_cm = None\n        self.frame_id = 0\n        self.target_miss_count = 0\n        self.last_target_rect = None\n        self.last_target_center = None\n        self.last_target_diameter_px = 0\n        self.last_target_corners = None\n        self.last_bullseye_center = None\n        self.bullseye_miss_count = 0\n        self.last_laser_spot = None\n        self.laser_miss_count = 0\n        self.circle_radius_px = 0.0\n        self.last_circle_radius_px = 0.0\n        self.target_center_history = []\n        self.bullseye_center_history = []\n        self.laser_spot_history = []\n        self.circle_radius_history = []\n        self.frozen_target_rect = None\n        self.frozen_target_center = None\n        self.frozen_target_diameter_px = 0\n        self.frozen_bullseye_center = None\n        self.predict_miss_count = 0\n\n    def detect_all(self, img):\n        self.frame_id += 1\n        self._detect_target(img)\n        if self.target_found:\n            self._detect_bullseye(img)\n            self.calibrate_scale()\n            self._detect_laser(img)\n            self._refresh_prediction_anchor()\n        else:\n            if self._prediction_available() and self.predict_miss_count < PREDICT_TRACK_MAX_FRAMES:\n                self.predict_miss_count += 1\n                self.target_rect = self.frozen_target_rect\n                self.target_center = self.frozen_target_center\n                self.target_diameter_px = self.frozen_target_diameter_px\n                self.bullseye_center = self.frozen_bullseye_center\n                self.bullseye_found = self.bullseye_plane_cm is not None\n                self._detect_laser(img)\n            else:\n                self.target_center = None\n                self.target_diameter_px = 0\n                self.bullseye_center = None\n                self.laser_spot = None\n                self.bullseye_found = False\n                self.laser_found = False\n\n    def _clamp_rect(self, x, y, w, h):\n        x = max(0, min(FRAME_WIDTH - 1, int(x)))\n        y = max(0, min(FRAME_HEIGHT - 1, int(y)))\n        w = max(1, min(FRAME_WIDTH - x, int(w)))\n        h = max(1, min(FRAME_HEIGHT - y, int(h)))\n        return (x, y, w, h)\n\n    def _distance_sq(self, p0, p1):\n        dx = p0[0] - p1[0]\n        dy = p0[1] - p1[1]\n        return dx * dx + dy * dy\n\n    def _clamp_point(self, point):\n        return (\n            max(0, min(FRAME_WIDTH - 1, int(point[0]))),\n            max(0, min(FRAME_HEIGHT - 1, int(point[1]))),\n        )\n\n    def _smooth_center(self, current, last_center, alpha, reset_px, sticky_px):\n        if last_center is None:\n            return current\n        dist_sq = self._distance_sq(current, last_center)\n        if dist_sq <= (sticky_px * sticky_px):\n            return last_center\n        if dist_sq > (reset_px * reset_px):\n            return current\n        return (\n            int(last_center[0] * (1 - alpha) + current[0] * alpha),\n            int(last_center[1] * (1 - alpha) + current[1] * alpha),\n        )\n\n    def _smooth_scalar(self, current, last_value, alpha):\n        if last_value <= 0:\n            return current\n        return last_value * (1 - alpha) + current * alpha\n\n    def _apply_motion_lead(self, current, last_center, gain, max_px):\n        if current is None or last_center is None or gain <= 0:\n            return current\n        dx = current[0] - last_center[0]\n        dy = current[1] - last_center[1]\n        lead_x = int(dx * gain)\n        lead_y = int(dy * gain)\n        if lead_x > max_px:\n            lead_x = max_px\n        elif lead_x < -max_px:\n            lead_x = -max_px\n        if lead_y > max_px:\n            lead_y = max_px\n        elif lead_y < -max_px:\n            lead_y = -max_px\n        return self._clamp_point((current[0] + lead_x, current[1] + lead_y))\n\n    def _solve_linear_system(self, matrix, values):\n        size = len(values)\n        a = []\n        for row in range(size):\n            current = []\n            for col in range(size):\n                current.append(float(matrix[row][col]))\n            current.append(float(values[row]))\n            a.append(current)\n\n        for col in range(size):\n            pivot = col\n            pivot_abs = abs(a[pivot][col])\n            for row in range(col + 1, size):\n                value_abs = abs(a[row][col])\n                if value_abs > pivot_abs:\n                    pivot = row\n                    pivot_abs = value_abs\n            if pivot_abs < 1e-6:\n                return None\n            if pivot != col:\n                tmp = a[col]\n                a[col] = a[pivot]\n                a[pivot] = tmp\n\n            pivot_value = a[col][col]\n            for idx in range(col, size + 1):\n                a[col][idx] /= pivot_value\n\n            for row in range(size):\n                if row == col:\n                    continue\n                factor = a[row][col]\n                for idx in range(col, size + 1):\n                    a[row][idx] -= factor * a[col][idx]\n\n        result = []\n        for row in range(size):\n            result.append(a[row][size])\n        return tuple(result)\n\n    def _compute_homography(self, src_points, dst_points):\n        matrix = []\n        values = []\n        for idx in range(4):\n            x = float(src_points[idx][0])\n            y = float(src_points[idx][1])\n            u = float(dst_points[idx][0])\n            v = float(dst_points[idx][1])\n            matrix.append([x, y, 1.0, 0.0, 0.0, 0.0, -u * x, -u * y])\n            values.append(u)\n            matrix.append([0.0, 0.0, 0.0, x, y, 1.0, -v * x, -v * y])\n            values.append(v)\n\n        solution = self._solve_linear_system(matrix, values)\n        if solution is None:\n            return None\n        return (\n            (solution[0], solution[1], solution[2]),\n            (solution[3], solution[4], solution[5]),\n            (solution[6], solution[7], 1.0),\n        )\n\n    def _apply_homography(self, h, x, y):\n        if h is None:\n            return None\n        denom = h[2][0] * x + h[2][1] * y + h[2][2]\n        if abs(denom) < 1e-6:\n            return None\n        out_x = (h[0][0] * x + h[0][1] * y + h[0][2]) / denom\n        out_y = (h[1][0] * x + h[1][1] * y + h[1][2]) / denom\n        return (out_x, out_y)\n\n    def _normalize_corners(self, corners):\n        sx = 0\n        sy = 0\n        points = []\n        for p in corners:\n            sx += p[0]\n            sy += p[1]\n            points.append((float(p[0]), float(p[1])))\n        center = (sx / 4, sy / 4)\n        points.sort(key=lambda p: math.atan2(p[1] - center[1], p[0] - center[0]))\n\n        top_left_idx = 0\n        best_score = points[0][0] + points[0][1]\n        for idx in range(1, 4):\n            score = points[idx][0] + points[idx][1]\n            if score < best_score:\n                best_score = score\n                top_left_idx = idx\n\n        ordered = []\n        for idx in range(4):\n            ordered.append(points[(top_left_idx + idx) % 4])\n        return ordered\n\n    def _plane_size_cm_for_corners(self, corners):\n        top = math.sqrt((corners[1][0] - corners[0][0]) ** 2 + (corners[1][1] - corners[0][1]) ** 2)\n        right = math.sqrt((corners[2][0] - corners[1][0]) ** 2 + (corners[2][1] - corners[1][1]) ** 2)\n        bottom = math.sqrt((corners[2][0] - corners[3][0]) ** 2 + (corners[2][1] - corners[3][1]) ** 2)\n        left = math.sqrt((corners[3][0] - corners[0][0]) ** 2 + (corners[3][1] - corners[0][1]) ** 2)\n        width_px = (top + bottom) * 0.5\n        height_px = (left + right) * 0.5\n        aspect = width_px / max(height_px, 1e-6)\n        normal_error = abs(aspect - TARGET_ASPECT)\n        swapped_error = abs(aspect - (1.0 / TARGET_ASPECT))\n        if swapped_error < normal_error:\n            return TARGET_HEIGHT_CM, TARGET_WIDTH_CM\n        return TARGET_WIDTH_CM, TARGET_HEIGHT_CM\n\n    def _point_to_target_plane_cm(self, point):\n        if self.image_to_target_h is None:\n            return None\n        projected = self._apply_homography(self.image_to_target_h, point[0], point[1])\n        if projected is None:\n            return None\n        return projected\n\n    def _prediction_available(self):\n        return (\n            self.frozen_target_rect is not None\n            and self.image_to_target_h is not None\n            and self.target_to_image_h is not None\n            and self.bullseye_plane_cm is not None\n        )\n\n    def _refresh_prediction_anchor(self):\n        if not self.bullseye_found:\n            return\n        if self.target_rect is not None:\n            self.frozen_target_rect = self.target_rect\n        if self.target_center is not None:\n            self.frozen_target_center = self.target_center\n        if self.target_diameter_px > 0:\n            self.frozen_target_diameter_px = self.target_diameter_px\n        if self.bullseye_center is not None:\n            self.frozen_bullseye_center = self.bullseye_center\n        self.predict_miss_count = 0\n\n    def _expand_rect(self, rect, margin):\n        x, y, w, h = rect\n        return self._clamp_rect(x - margin, y - margin, w + margin * 2, h + margin * 2)\n\n    def _push_point_history(self, history, point, max_len):\n        history.append(point)\n        if len(history) > max_len:\n            history.pop(0)\n        return history\n\n    def _filter_point_history(self, history):\n        if not history:\n            return None\n        xs = sorted(point[0] for point in history)\n        ys = sorted(point[1] for point in history)\n        mid = len(history) // 2\n        return (xs[mid], ys[mid])\n\n    def _push_scalar_history(self, history, value, max_len):\n        history.append(value)\n        if len(history) > max_len:\n            history.pop(0)\n        return history\n\n    def _filter_scalar_history(self, history):\n        if not history:\n            return 0.0\n        values = sorted(history)\n        return values[len(values) // 2]\n\n    def _rect_aspect_error(self, w, h):\n        aspect = w / max(h, 1)\n        target_inv = 1.0 / TARGET_ASPECT\n        return min(abs(aspect - TARGET_ASPECT), abs(aspect - target_inv))\n\n    def _rect_center_from_corners(self, corners):\n        sx = 0\n        sy = 0\n        points = []\n        for p in corners:\n            sx += p[0]\n            sy += p[1]\n            points.append((p[0], p[1]))\n        avg_center = (sx / 4, sy / 4)\n\n        points.sort(key=lambda p: math.atan2(p[1] - avg_center[1], p[0] - avg_center[0]))\n        p0 = points[0]\n        p1 = points[1]\n        p2 = points[2]\n        p3 = points[3]\n\n        x1 = p0[0]\n        y1 = p0[1]\n        x2 = p2[0]\n        y2 = p2[1]\n        x3 = p1[0]\n        y3 = p1[1]\n        x4 = p3[0]\n        y4 = p3[1]\n\n        denom = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4)\n        if abs(denom) < 1:\n            return self._clamp_point(avg_center)\n\n        det1 = x1 * y2 - y1 * x2\n        det2 = x3 * y4 - y3 * x4\n        center_x = (det1 * (x3 - x4) - (x1 - x2) * det2) / denom\n        center_y = (det1 * (y3 - y4) - (y1 - y2) * det2) / denom\n        if center_x < -8 or center_x > (FRAME_WIDTH + 8) or center_y < -8 or center_y > (FRAME_HEIGHT + 8):\n            return self._clamp_point(avg_center)\n        return self._clamp_point((center_x, center_y))\n\n    def _rect_size_change_ok(self, rect, last_rect):\n        if last_rect is None:\n            return True\n        _, _, w, h = rect\n        _, _, last_w, last_h = last_rect\n        if last_w <= 0 or last_h <= 0:\n            return True\n        dw = abs(w - last_w) / last_w\n        dh = abs(h - last_h) / last_h\n        return dw <= TARGET_MAX_SIZE_CHANGE_RATIO and dh <= TARGET_MAX_SIZE_CHANGE_RATIO\n\n    def _compensate_edge_rect(self, rect, last_rect):\n        if last_rect is None:\n            return rect\n        x, y, w, h = rect\n        _, _, last_w, last_h = last_rect\n        if last_w <= 0 or last_h <= 0:\n            return rect\n\n        x2 = x + w\n        y2 = y + h\n        if x <= TARGET_EDGE_MARGIN_PX and w < int(last_w * TARGET_EDGE_COMP_MIN_RATIO):\n            w = last_w\n            x2 = x + w\n        elif x2 >= (FRAME_WIDTH - TARGET_EDGE_MARGIN_PX) and w < int(last_w * TARGET_EDGE_COMP_MIN_RATIO):\n            x = max(0, x2 - last_w)\n            w = FRAME_WIDTH - x if x + last_w > FRAME_WIDTH else last_w\n\n        if y <= TARGET_EDGE_MARGIN_PX and h < int(last_h * TARGET_EDGE_COMP_MIN_RATIO):\n            h = last_h\n            y2 = y + h\n        elif y2 >= (FRAME_HEIGHT - TARGET_EDGE_MARGIN_PX) and h < int(last_h * TARGET_EDGE_COMP_MIN_RATIO):\n            y = max(0, y2 - last_h)\n            h = FRAME_HEIGHT - y if y + last_h > FRAME_HEIGHT else last_h\n\n        return self._clamp_rect(x, y, w, h)\n\n    def _rect_overlap_ratio(self, rect_a, rect_b):\n        if rect_a is None or rect_b is None:\n            return 0.0\n        ax, ay, aw, ah = rect_a\n        bx, by, bw, bh = rect_b\n        ax2 = ax + aw\n        ay2 = ay + ah\n        bx2 = bx + bw\n        by2 = by + bh\n        ix1 = max(ax, bx)\n        iy1 = max(ay, by)\n        ix2 = min(ax2, bx2)\n        iy2 = min(ay2, by2)\n        iw = ix2 - ix1\n        ih = iy2 - iy1\n        if iw <= 0 or ih <= 0:\n            return 0.0\n        inter = iw * ih\n        min_area = min(max(1, aw * ah), max(1, bw * bh))\n        return inter / min_area\n\n    def _rect_border_hit_ratio(self, rect_img, rect):\n        x, y, w, h = rect\n        if w <= 4 or h <= 4:\n            return 0.0\n        inset = max(1, min(6, min(w, h) // 12))\n        x1 = x + inset\n        y1 = y + inset\n        x2 = x + w - 1 - inset\n        y2 = y + h - 1 - inset\n        if x2 <= x1 or y2 <= y1:\n            return 0.0\n\n        hits = 0\n        total = 0\n        steps = max(4, TARGET_BORDER_SAMPLE_COUNT)\n        for idx in range(steps):\n            t = idx / max(1, steps - 1)\n            sx = int(x1 + (x2 - x1) * t)\n            sy = int(y1 + (y2 - y1) * t)\n            points = (\n                (sx, y1),\n                (sx, y2),\n                (x1, sy),\n                (x2, sy),\n            )\n            for px, py in points:\n                total += 1\n                try:\n                    if rect_img.get_pixel(px, py):\n                        hits += 1\n                except Exception:\n                    pass\n        if total <= 0:\n            return 0.0\n        return hits / total\n\n    def _select_best_rect(self, rect_img, rects, reference_center, reference_rect):\n        best = None\n        best_score = None\n        image_center = (FRAME_WIDTH // 2, FRAME_HEIGHT // 2)\n\n        for r in rects:\n            raw_rect = r.rect()\n            corners = r.corners()\n            if raw_rect is None or corners is None or len(corners) != 4:\n                continue\n            rect = self._compensate_edge_rect(raw_rect, reference_rect)\n            x, y, w, h = rect\n            if w < TARGET_MIN_W or h < TARGET_MIN_H:\n                continue\n            area = w * h\n            if area < TARGET_MIN_AREA:\n                continue\n            if not self._rect_size_change_ok(rect, reference_rect):\n                continue\n\n            center = self._rect_center_from_corners(corners)\n            border_hit_ratio = self._rect_border_hit_ratio(rect_img, rect)\n            if border_hit_ratio < TARGET_BORDER_HIT_RATIO_MIN:\n                continue\n            if reference_center is not None:\n                jump_sq = self._distance_sq(center, reference_center)\n                if jump_sq > (TARGET_RESET_DIST_PX * TARGET_RESET_DIST_PX):\n                    continue\n            if reference_rect is not None:\n                overlap_ratio = self._rect_overlap_ratio(rect, reference_rect)\n                if overlap_ratio < TARGET_MIN_OVERLAP_RATIO and (\n                    reference_center is None\n                    or self._distance_sq(center, reference_center) > (TARGET_STICKY_DIST_PX * TARGET_STICKY_DIST_PX)\n                ):\n                    continue\n            aspect_penalty = int(self._rect_aspect_error(w, h) * TARGET_ASPECT_PENALTY_SCALE)\n            if reference_center is not None:\n                distance_penalty = self._distance_sq(center, reference_center) // 10\n            else:\n                distance_penalty = self._distance_sq(center, image_center) // TARGET_INIT_CENTER_BIAS\n            edge_penalty = 0\n            if x <= 2 or y <= 2 or (x + w) >= (FRAME_WIDTH - 2) or (y + h) >= (FRAME_HEIGHT - 2):\n                edge_penalty = 3600\n            center_bias_bonus = 0\n            if self._distance_sq(center, image_center) <= (TARGET_NEAR_CENTER_PX * TARGET_NEAR_CENTER_PX):\n                center_bias_bonus = 2000\n            border_score_bonus = int(border_hit_ratio * TARGET_BORDER_SCORE_SCALE)\n\n            score = area - aspect_penalty - distance_penalty - edge_penalty + center_bias_bonus + border_score_bonus\n            if best_score is None or score > best_score:\n                best_score = score\n                best = (rect, corners, center)\n\n        return best\n\n    def _accept_center(self, candidate_center, last_center):\n        if candidate_center is None or last_center is None:\n            return True\n        return self._distance_sq(candidate_center, last_center) <= (TARGET_MAX_JUMP_PX * TARGET_MAX_JUMP_PX)\n\n    def _prepare_rect_image(self, img):\n        rect_img = img.to_grayscale()\n        rect_img.binary([RECT_BINARY_THRESHOLD])\n        return rect_img\n\n    def _refine_bullseye_center(self, img):\n        if not (self.target_rect and self.target_center):\n            return self.target_center\n\n        x, y, w, h = self.target_rect\n        roi_w = max(12, int(w * BULLSEYE_ROI_RATIO))\n        roi_h = max(12, int(h * BULLSEYE_ROI_RATIO))\n        cx, cy = self.target_center\n        roi_x = max(x, cx - roi_w // 2)\n        roi_y = max(y, cy - roi_h // 2)\n        roi_x2 = min(x + w, roi_x + roi_w)\n        roi_y2 = min(y + h, roi_y + roi_h)\n        roi = (\n            roi_x,\n            roi_y,\n            max(1, roi_x2 - roi_x),\n            max(1, roi_y2 - roi_y),\n        )\n\n        blobs = img.find_blobs(\n            [BLACK_THRESHOLD],\n            roi=roi,\n            pixels_threshold=3,\n            area_threshold=3,\n            merge=True,\n        ) or []\n        if not blobs:\n            return self.target_center\n\n        gate_px = max(6, int(min(w, h) * BULLSEYE_GATE_RATIO * 0.5))\n        gate_sq = gate_px * gate_px\n        weighted_x = 0.0\n        weighted_y = 0.0\n        total_weight = 0.0\n        for blob in blobs:\n            bx = blob.cx()\n            by = blob.cy()\n            dist_sq = self._distance_sq((bx, by), self.target_center)\n            if dist_sq > gate_sq:\n                continue\n            weight = max(1.0, float(blob.pixels()))\n            weighted_x += bx * weight\n            weighted_y += by * weight\n            total_weight += weight\n\n        if total_weight <= 0:\n            return self.target_center\n\n        refined = (\n            int(weighted_x / total_weight),\n            int(weighted_y / total_weight),\n        )\n        return (\n            int(self.target_center[0] * (1 - BULLSEYE_BLEND_ALPHA) + refined[0] * BULLSEYE_BLEND_ALPHA),\n            int(self.target_center[1] * (1 - BULLSEYE_BLEND_ALPHA) + refined[1] * BULLSEYE_BLEND_ALPHA),\n        )\n\n    def _detect_target(self, img):\n        if self.target_found and (self.frame_id % TARGET_DETECT_INTERVAL) != 0:\n            return\n\n        previous_rect = self.last_target_rect\n        previous_center = self.last_target_center\n        previous_diameter = self.last_target_diameter_px\n        previous_corners = self.last_target_corners\n        self.target_rect = None\n        self.target_center = None\n        self.target_diameter_px = 0\n        self.target_found = False\n\n        rect_img = self._prepare_rect_image(img)\n        rects = rect_img.find_rects(threshold=RECT_THRESHOLD) or []\n        chosen = self._select_best_rect(rect_img, rects, previous_center, previous_rect)\n        if chosen is not None:\n            _, _, center = chosen\n            if not self._accept_center(center, previous_center):\n                chosen = None\n\n        if chosen is None:\n            self.target_miss_count += 1\n            if previous_rect and previous_center and self.target_miss_count <= TARGET_MAX_MISS_FRAMES:\n                self.target_rect = previous_rect\n                self.target_center = previous_center\n                self.target_diameter_px = previous_diameter\n                self.last_target_corners = previous_corners\n                self.target_found = True\n            else:\n                self.last_target_rect = None\n                self.last_target_center = None\n                self.last_target_diameter_px = 0\n                self.last_target_corners = None\n                self.target_center_history = []\n                self.bullseye_center_history = []\n                self.laser_spot_history = []\n                self.circle_radius_history = []\n                self.circle_radius_px = 0.0\n                self.last_circle_radius_px = 0.0\n            return None\n\n        self.target_miss_count = 0\n        rect, corners, center = chosen\n        self.target_rect = rect\n        self.target_center = self._smooth_center(\n            center,\n            previous_center,\n            TARGET_CENTER_ALPHA,\n            TARGET_RESET_DIST_PX,\n            TARGET_STICKY_DIST_PX,\n        )\n        self.target_center = self._apply_motion_lead(\n            self.target_center,\n            previous_center,\n            TARGET_LEAD_GAIN,\n            TARGET_LEAD_MAX_PX,\n        )\n        self.target_diameter_px = min(rect[2], rect[3])\n        self.target_found = True\n        self.last_target_rect = self.target_rect\n        self.last_target_corners = corners\n        self.last_target_center = self.target_center\n        self.last_target_diameter_px = self.target_diameter_px\n\n        return self.target_rect\n\n    def _detect_bullseye(self, img):\n        self.bullseye_found = False\n        self.bullseye_center = None\n        if not (self.target_found and self.target_rect and self.target_center):\n            return\n        if (\n            self.last_bullseye_center is not None\n            and (self.frame_id % BULLSEYE_DETECT_INTERVAL) != 0\n        ):\n            self.bullseye_center = self.last_bullseye_center\n            self.bullseye_found = True\n            return\n\n        refined_center = self._refine_bullseye_center(img)\n        self.bullseye_center = self._smooth_center(\n            refined_center,\n            self.last_bullseye_center,\n            BULLSEYE_CENTER_ALPHA,\n            TARGET_RESET_DIST_PX,\n            TARGET_STICKY_DIST_PX,\n        )\n        self.bullseye_center = self._apply_motion_lead(\n            self.bullseye_center,\n            self.last_bullseye_center,\n            BULLSEYE_LEAD_GAIN,\n            BULLSEYE_LEAD_MAX_PX,\n        )\n        self.last_bullseye_center = self.bullseye_center\n        self.bullseye_found = True\n        self.bullseye_miss_count = 0\n\n    def _detect_laser(self, img):\n        self.laser_spot = None\n        self.laser_found = False\n        if self.target_rect is None:\n            return None\n        roi = self.target_rect\n        if not self.target_found:\n            margin = max(LASER_PREDICT_ROI_MARGIN_PX, self.target_diameter_px // 2)\n            roi = self._expand_rect(roi, margin)\n\n        blobs = img.find_blobs(\n            [VIOLET_THRESHOLD],\n            roi=roi,\n            pixels_threshold=2,\n            area_threshold=2,\n            merge=True,\n        )\n        if blobs:\n            reference = self.last_laser_spot or self.target_center\n            gate_px = max(5, self.target_diameter_px // 10)\n            gate_sq = gate_px * gate_px\n            candidate_blobs = [\n                blob\n                for blob in blobs\n                if self._distance_sq((blob.cx(), blob.cy()), reference) <= gate_sq\n            ]\n            if not candidate_blobs:\n                candidate_blobs = blobs\n            best = min(\n                candidate_blobs,\n                key=lambda b: (\n                    self._distance_sq((b.cx(), b.cy()), reference),\n                    -b.density(),\n                ),\n            )\n            raw_spot = (best.cx(), best.cy())\n            self.laser_spot = self._smooth_center(\n                raw_spot,\n                self.last_laser_spot,\n                0.9,\n                LASER_STICKY_PX * 3,\n                LASER_STICKY_PX,\n            )\n            self._push_point_history(\n                self.laser_spot_history,\n                self.laser_spot,\n                LASER_POINT_HISTORY_LEN,\n            )\n            self.laser_spot = self._filter_point_history(self.laser_spot_history)\n            self.laser_found = True\n            self.last_laser_spot = self.laser_spot\n            self.laser_miss_count = 0\n            return self.laser_spot\n\n        self.laser_miss_count += 1\n        if self.last_laser_spot is not None and self.laser_miss_count <= LASER_MAX_MISS_FRAMES:\n            self.laser_spot = self.last_laser_spot\n            self._push_point_history(\n                self.laser_spot_history,\n                self.laser_spot,\n                LASER_POINT_HISTORY_LEN,\n            )\n            self.laser_spot = self._filter_point_history(self.laser_spot_history)\n            self.laser_found = True\n            return self.laser_spot\n\n        self.laser_spot_history = []\n        return None\n\n    def calibrate_scale(self):\n        self.pixel_to_cm_ratio_x = 0.0\n        self.pixel_to_cm_ratio_y = 0.0\n        self.target_to_image_h = None\n        self.image_to_target_h = None\n        self.bullseye_plane_cm = None\n        if not (self.target_found and self.last_target_corners):\n            return False\n\n        corners = self.last_target_corners\n        ordered_corners = self._normalize_corners(corners)\n        width_cm, height_cm = self._plane_size_cm_for_corners(ordered_corners)\n        plane_corners = (\n            (-width_cm * 0.5, height_cm * 0.5),\n            (width_cm * 0.5, height_cm * 0.5),\n            (width_cm * 0.5, -height_cm * 0.5),\n            (-width_cm * 0.5, -height_cm * 0.5),\n        )\n        self.target_plane_corners_cm = plane_corners\n        self.target_to_image_h = self._compute_homography(plane_corners, ordered_corners)\n        self.image_to_target_h = self._compute_homography(ordered_corners, plane_corners)\n        edges = []\n        for idx in range(4):\n            p0 = ordered_corners[idx]\n            p1 = ordered_corners[(idx + 1) % 4]\n            dx = p0[0] - p1[0]\n            dy = p0[1] - p1[1]\n            edges.append(math.sqrt(dx * dx + dy * dy))\n\n        width_px = (edges[0] + edges[2]) * 0.5\n        height_px = (edges[1] + edges[3]) * 0.5\n        if width_px <= 0 or height_px <= 0:\n            width_px = self.target_rect[2]\n            height_px = self.target_rect[3]\n        if width_px <= 0 or height_px <= 0:\n            return False\n\n        self.pixel_to_cm_ratio_x = width_cm / width_px\n        self.pixel_to_cm_ratio_y = height_cm / height_px\n\n        radius_px = (\n            (CIRCLE_RADIUS_CM / self.pixel_to_cm_ratio_x)\n            + (CIRCLE_RADIUS_CM / self.pixel_to_cm_ratio_y)\n        ) * 0.5\n        self.circle_radius_px = self._smooth_scalar(\n            radius_px,\n            self.last_circle_radius_px,\n            CIRCLE_RADIUS_SMOOTHING_ALPHA,\n        )\n        self._push_scalar_history(\n            self.circle_radius_history,\n            self.circle_radius_px,\n            RADIUS_HISTORY_LEN,\n        )\n        self.circle_radius_px = self._filter_scalar_history(self.circle_radius_history)\n        self.last_circle_radius_px = self.circle_radius_px\n        if self.bullseye_found and self.bullseye_center:\n            self.bullseye_plane_cm = self._point_to_target_plane_cm(self.bullseye_center)\n        return True\n\n    def pixel_offset_to_cm(self, pixel_dx, pixel_dy):\n        return (\n            pixel_dx * self.pixel_to_cm_ratio_x,\n            pixel_dy * self.pixel_to_cm_ratio_y,\n        )\n\n    def get_offset_info(self):\n        if not self.bullseye_found or not self.laser_found:\n            return None\n\n        bx, by = self.bullseye_center\n        lx, ly = self.laser_spot\n        laser_plane_cm = self._point_to_target_plane_cm(self.laser_spot)\n        if self.bullseye_plane_cm is not None and laser_plane_cm is not None:\n            dx_cm = laser_plane_cm[0] - self.bullseye_plane_cm[0]\n            dy_cm = laser_plane_cm[1] - self.bullseye_plane_cm[1]\n        else:\n            dx_cm, dy_cm = self.pixel_offset_to_cm(lx - bx, ly - by)\n        distance_cm = math.sqrt(dx_cm * dx_cm + dy_cm * dy_cm)\n        angle_deg = math.degrees(math.atan2(-dy_cm, dx_cm))\n        return {\n            "dx_cm": dx_cm,\n            "dy_cm": dy_cm,\n            "distance_cm": distance_cm,\n            "angle_deg": angle_deg,\n            "laser_px": (lx, ly),\n            "target_px": (bx, by),\n        }\n\n\nclass CircleTrajectory:\n    def __init__(self, radius_cm=CIRCLE_RADIUS_CM, points_per_circle=360):\n        self.radius_cm = radius_cm\n        self.points_per_circle = points_per_circle\n        self.angle_step = 2 * math.pi / points_per_circle\n        self.reset()\n\n    def get_target_point(self):\n        dx = self.radius_cm * math.cos(self.current_angle)\n        dy = self.radius_cm * math.sin(self.current_angle)\n        self.current_angle += self.angle_step\n        if self.current_angle >= 2 * math.pi:\n            self.current_angle -= 2 * math.pi\n        return dx, dy\n\n    def reset(self):\n        self.current_angle = 0.0\n\n\nclass AimingSystem:\n    def __init__(self, uart_id=2, tx_pin=5, rx_pin=6):\n        self.detector = TargetDetector()\n        self.trajectory = CircleTrajectory(CIRCLE_RADIUS_CM)\n        self.uart = None\n        self.comm_started = False\n        self.start_button = StartButton(START_BUTTON_BOARD_PIN, START_BUTTON_GPIO_NUM)\n        self.uart_id = uart_id\n        self.tx_pin = tx_pin\n        self.rx_pin = rx_pin\n        self.mode = "aim"\n        self.frame_count = 0\n        self.fps = 0.0\n        self.last_fps_time = time.ticks_ms()\n        self.gc_counter = 0\n\n    def init_uart(self):\n        try:\n            fpioa = FPIOA()\n            fpioa.set_function(self.tx_pin, fpioa.UART2_TXD)\n            fpioa.set_function(self.rx_pin, fpioa.UART2_RXD)\n            self.uart = UART(self.uart_id, baudrate=UART_BAUDRATE)\n            print(f"[UART] init ok: {UART_BAUDRATE}")\n            return True\n        except Exception as e:\n            print(f"[UART] init failed: {e}")\n            return False\n\n    def send_aiming_data(self, offset_info):\n        if self.uart is None or not self.comm_started:\n            return\n        if offset_info is None:\n            self.uart.write("AIM,SEARCH\\n")\n            return\n        self.uart.write(\n            "AIM,{:.2f},{:.2f},{:.2f},{:.1f}\\n".format(\n                offset_info["dx_cm"],\n                offset_info["dy_cm"],\n                offset_info["distance_cm"],\n                offset_info["angle_deg"],\n            )\n        )\n\n    def send_circle_data(self, target_dx, target_dy, current_offset):\n        if self.uart is None or not self.comm_started:\n            return\n        cur_dx = current_offset["dx_cm"] if current_offset else 0\n        cur_dy = current_offset["dy_cm"] if current_offset else 0\n        self.uart.write(\n            "CIR,{:.2f},{:.2f},{:.2f},{:.2f}\\n".format(\n                target_dx, target_dy, cur_dx, cur_dy\n            )\n        )\n\n    def send_status(self, status):\n        if self.uart and self.comm_started:\n            self.uart.write("STS,{}\\n".format(status))\n\n    def _update_start_button(self):\n        if self.comm_started:\n            return\n        if self.start_button.poll_pressed():\n            self.comm_started = True\n            print("[Comm] start button pressed, UART enabled")\n            self.send_status(self.mode.upper())\n\n    def process_frame(self, img):\n        self.frame_count += 1\n        self.gc_counter += 1\n        self._update_start_button()\n\n        self.detector.detect_all(img)\n        offset_info = self.detector.get_offset_info()\n\n        if self.mode == "aim":\n            self.send_aiming_data(offset_info)\n        elif self.mode == "circle":\n            target_dx, target_dy = self.trajectory.get_target_point()\n            self.send_circle_data(target_dx, target_dy, offset_info)\n\n        if DEBUG_MODE:\n            self._draw_debug_overlay(img, offset_info)\n\n        return img\n\n    def _draw_debug_overlay(self, img, offset_info):\n        if self.detector.target_found and self.detector.target_rect:\n            x, y, w, h = self.detector.target_rect\n            img.draw_rectangle(x, y, w, h, color=(0, 255, 0), thickness=1)\n        if self.detector.target_found and self.detector.target_center:\n            cx, cy = self.detector.target_center\n            img.draw_cross(cx, cy, color=(0, 255, 0), size=8, thickness=1)\n\n        if self.detector.laser_found and self.detector.laser_spot:\n            cx, cy = self.detector.laser_spot\n            img.draw_circle(cx, cy, 4, color=(255, 255, 0), thickness=1)\n            if self.detector.bullseye_found and self.detector.bullseye_center:\n                bx, by = self.detector.bullseye_center\n                img.draw_line(cx, cy, bx, by, color=(0, 255, 255), thickness=1)\n\n        if DEBUG_TEXT_OVERLAY:\n            if offset_info:\n                draw_text(\n                    img,\n                    4,\n                    4,\n                    "D={:.1f} A={:.0f}".format(\n                        offset_info["distance_cm"], offset_info["angle_deg"]\n                    ),\n                    color=(255, 255, 255),\n                    scale=1,\n                )\n\n            draw_text(\n                img,\n                4,\n                FRAME_HEIGHT - 16,\n                "Mode: {}".format(self.mode.upper()),\n                color=(0, 255, 0),\n                scale=1,\n            )\n            draw_text(\n                img,\n                FRAME_WIDTH - 70,\n                4,\n                "FPS:{:.1f}".format(self.fps),\n                color=(255, 255, 255),\n                scale=1,\n            )\n        if not self.comm_started:\n            draw_text(\n                img,\n                4,\n                FRAME_HEIGHT - 16,\n                "PRESS GPIO28 TO START UART",\n                color=(255, 255, 0),\n                scale=1,\n            )\n\n    def update_fps(self):\n        current_time = time.ticks_ms()\n        dt = time.ticks_diff(current_time, self.last_fps_time)\n        if dt >= 1000:\n            self.fps = self.frame_count * 1000 / dt\n            self.frame_count = 0\n            self.last_fps_time = current_time\n\n    def maybe_collect_gc(self):\n        if self.gc_counter >= GC_INTERVAL:\n            gc.collect()\n            self.gc_counter = 0\n\n    def set_mode(self, mode):\n        if mode in ("aim", "circle", "idle"):\n            self.mode = mode\n            if mode == "circle":\n                self.trajectory.reset()\n            self.send_status(mode.upper())\n            print(f"[Mode] {mode}")\n\n\ndef main():\n    print("=" * 50)\n    print("K230 aiming system")\n    print("build:", BUILD_TAG)\n    print("fast mode enabled")\n    print("=" * 50)\n    apply_calibration()\n\n    aiming_system = AimingSystem(uart_id=2, tx_pin=5, rx_pin=6)\n    aiming_system.init_uart()\n\n    print("[Display] init...")\n    init_preview_display()\n    try:\n        print("[Sensor] init...")\n        sensor = init_camera_sensor()\n        start_camera(sensor)\n    except Exception as e:\n        print(f"[Sensor] start failed, retry by restart: {e}")\n        sensor = restart_camera(None)\n\n    aiming_system.set_mode("aim")\n    print("[System] ready")\n\n    consecutive_snapshot_failures = 0\n    try:\n        while True:\n            os.exitpoint()\n            try:\n                img = snapshot_with_retry(sensor)\n                consecutive_snapshot_failures = 0\n            except RuntimeError as e:\n                consecutive_snapshot_failures += 1\n                if consecutive_snapshot_failures >= MAX_CONSECUTIVE_SNAPSHOT_FAILURES:\n                    print(f"[Sensor] snapshot failed repeatedly, restart: {e}")\n                    sensor = restart_camera(sensor)\n                    consecutive_snapshot_failures = 0\n                time.sleep_ms(FRAME_LOOP_DELAY_MS)\n                continue\n            img = aiming_system.process_frame(img)\n            aiming_system.update_fps()\n            Display.show_image(img)\n            aiming_system.maybe_collect_gc()\n            time.sleep_ms(FRAME_LOOP_DELAY_MS)\n    except KeyboardInterrupt:\n        print("\\n[System] interrupted")\n    except Exception as e:\n        print(f"[Error] {e}")\n        sys.print_exception(e)\n    finally:\n        print("[System] cleanup...")\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n        Display.deinit()\n        os.exitpoint(os.EXITPOINT_ENABLE_SLEEP)\n        time.sleep_ms(100)\n        MediaManager.deinit()\n        Sensor.deinit()\n        if aiming_system.uart:\n            aiming_system.uart.deinit()\n        print("[System] stopped")\n\n\ndef main_test():\n    print("K230 aiming system - test mode")\n    apply_calibration()\n\n    sensor = init_camera_sensor()\n    init_preview_display()\n    try:\n        start_camera(sensor)\n    except Exception as e:\n        print(f"[Sensor] start failed in test, retry by restart: {e}")\n        sensor = restart_camera(sensor)\n    detector = TargetDetector()\n    clock = time.clock()\n    frame_count = 0\n\n    try:\n        while True:\n            os.exitpoint()\n            clock.tick()\n            frame_count += 1\n\n            try:\n                img = snapshot_with_retry(sensor)\n            except RuntimeError as e:\n                print(f"[Sensor] snapshot failed in test, restart: {e}")\n                sensor = restart_camera(sensor)\n                img = snapshot_with_retry(sensor)\n            detector.detect_all(img)\n            offset = detector.get_offset_info()\n\n            if frame_count % 30 == 0:\n                print("-" * 40)\n                print(\n                    "target:{} bullseye:{} laser:{}".format(\n                        detector.target_found,\n                        detector.bullseye_found,\n                        detector.laser_found,\n                    )\n                )\n                if offset:\n                    print(\n                        "offset dx={:.2f} dy={:.2f} dist={:.2f} angle={:.1f}".format(\n                            offset["dx_cm"],\n                            offset["dy_cm"],\n                            offset["distance_cm"],\n                            offset["angle_deg"],\n                        )\n                    )\n                print("FPS: {:.1f}".format(clock.fps()))\n\n            if frame_count % GC_INTERVAL == 0:\n                gc.collect()\n            time.sleep_ms(FRAME_LOOP_DELAY_MS)\n    except KeyboardInterrupt:\n        print("\\nstop test")\n    except Exception as e:\n        print(f"error: {e}")\n        sys.print_exception(e)\n    finally:\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n        Display.deinit()\n        os.exitpoint(os.EXITPOINT_ENABLE_SLEEP)\n        time.sleep_ms(100)\n        MediaManager.deinit()\n        Sensor.deinit()\n        print("test finished")\n\n\nif __name__ == "__main__":\n    main()\n'
CIRCLE_MODE_SOURCE = 'from media.sensor import *\nfrom media.display import *\nfrom media.media import *\nimport gc\nimport math\nimport os\nimport sys\nimport time\nfrom machine import FPIOA, Pin, UART\n\ntry:\n    from k230_common import load_calibration\nexcept ImportError:\n    def load_calibration(default_red, default_black, default_violet, default_bright=None):\n        return (\n            False,\n            tuple(default_red),\n            tuple(default_black),\n            tuple(default_violet),\n            default_bright,\n        )\n\n\nCAMERA_ID = 2\nFRAME_WIDTH = 416\nFRAME_HEIGHT = 234\nSENSOR_HMIRROR = True\nSENSOR_VFLIP = True\n\nTARGET_WIDTH_CM = 25.0\nTARGET_HEIGHT_CM = 29.7\nCIRCLE_RADIUS_CM = 6.0\nTARGET_OUTER_DIAMETER_CM = 21.0\n\nRED_THRESHOLD = (41, 100, -28, 6, -14, 14)\nBLACK_THRESHOLD = (22, 69, -23, -3, -22, 16)\nRING_THRESHOLD = (43, 74, -28, -1, -17, 19)\nVIOLET_THRESHOLD = (92, 100, -15, 6, -9, 11)\n\nRECT_THRESHOLD = 8000\nRECT_BINARY_THRESHOLD = (0, 72)\nTARGET_MIN_W = 44\nTARGET_MIN_H = 44\nTARGET_MIN_AREA = 3600\nTARGET_ASPECT = TARGET_WIDTH_CM / TARGET_HEIGHT_CM\nTARGET_ASPECT_PENALTY_SCALE = 12000\nTARGET_CENTER_ALPHA = 0.90\nTARGET_RESET_DIST_PX = 144\nTARGET_STICKY_DIST_PX = 1\nTARGET_LEAD_GAIN = 0.12\nTARGET_LEAD_MAX_PX = 12\nTARGET_MAX_JUMP_PX = 96\nTARGET_MAX_SIZE_CHANGE_RATIO = 0.35\nTARGET_EDGE_MARGIN_PX = 4\nTARGET_EDGE_COMP_MIN_RATIO = 0.55\nTARGET_MIN_OVERLAP_RATIO = 0.18\nTARGET_INIT_CENTER_BIAS = 14\nTARGET_NEAR_CENTER_PX = 180\nTARGET_BORDER_SAMPLE_COUNT = 10\nTARGET_BORDER_HIT_RATIO_MIN = 0.32\nTARGET_BORDER_SCORE_SCALE = 9000\nBULLSEYE_ROI_RATIO = 0.42\nBULLSEYE_GATE_RATIO = 0.60\nBULLSEYE_BLEND_ALPHA = 0.65\nBULLSEYE_CENTER_ALPHA = 0.84\nBULLSEYE_LEAD_GAIN = 0.18\nBULLSEYE_LEAD_MAX_PX = 10\n\nNUM_WAYPOINTS = 360\nMAX_SYNC_ERROR_DEG = 90\nSTART_ALIGN_TOL_CM = 1.2\nSTART_ALIGN_HOLD_FRAMES = 3\nCIRCLE_SPEED_DEG_PER_SEC = 20.0\n\nPID_KP = 0.8\nPID_KI = 0.1\nPID_KD = 0.05\n\nUART_ID = 2\nTX_PIN = 5\nRX_PIN = 6\nUART_BAUDRATE = 115200\nSTART_BUTTON_BOARD_PIN = 28\nSTART_BUTTON_GPIO_NUM = 28\nBUTTON_DEBOUNCE_MS = 35\n\nDEBUG_MODE = True\nDEBUG_TEXT_OVERLAY = False\nTARGET_DETECT_INTERVAL = 1\nBULLSEYE_DETECT_INTERVAL = 1\nRING_DETECT_INTERVAL = 3\nPREDICT_TRACK_MAX_FRAMES = 45\nTARGET_MAX_MISS_FRAMES = 6\nLASER_MAX_MISS_FRAMES = 2\nLASER_STICKY_PX = 2\nLASER_PREDICT_ROI_MARGIN_PX = 28\nCIRCLE_RADIUS_SMOOTHING_ALPHA = 0.45\nRING_RADIUS_CLUSTER_TOL_CM = 0.35\nRING_RADIUS_MIN_CM = 1.5\nRING_RADIUS_MAX_CM = 12.0\nRING_TARGET_INDEX_FROM_CENTER = 2\nRING_MIN_CLUSTER_SAMPLES = 2\nRING_MIN_CLUSTER_WEIGHT = 3.0\nRING_BLOB_MIN_SIZE_PX = 2\nRING_BLOB_MAX_SIZE_DIV = 8\nPOINT_HISTORY_LEN = 1\nDISPLAY_FPS = 30\nFRAME_LOOP_DELAY_MS = 0\nSNAPSHOT_RETRY_COUNT = 3\nSNAPSHOT_RETRY_DELAY_MS = 3\nSENSOR_WARMUP_FRAMES = 2\nSTART_CAMERA_RETRY_COUNT = 2\nSTART_CAMERA_RETRY_DELAY_MS = 10\nSTART_CAMERA_SETTLE_MS = 28\nSTART_CAMERA_SETTLE_STEP_MS = 18\nALLOW_CHANNEL_FALLBACK = False\nOVERLAY_RING_SAMPLE_COUNT = 18\nGC_FRAME_INTERVAL = 180\nBUILD_TAG = "2026-07-14-circle-fastboot-v31"\nCURRENT_SNAPSHOT_CHN = CAM_CHN_ID_1\nERROR_JUMP_MAX_CM = 3.0\nERROR_JUMP_REJECT_FRAMES = 2\n\n\ndef apply_calibration():\n    global RED_THRESHOLD, BLACK_THRESHOLD, VIOLET_THRESHOLD\n    ok, red, black, violet, _ = load_calibration(\n        RED_THRESHOLD, BLACK_THRESHOLD, VIOLET_THRESHOLD\n    )\n    RED_THRESHOLD = red\n    BLACK_THRESHOLD = black\n    VIOLET_THRESHOLD = violet\n    if ok:\n        print("[Calib] thresholds applied")\n    else:\n        print("[Calib] using built-in thresholds")\n\n\ndef _snapshot_channel_name(snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return "chn1"\n    return "chn0"\n\n\ndef _configure_sensor_for_channel(sensor, camera_id, snapshot_chn):\n    sensor.reset()\n    try:\n        sensor.set_hmirror(SENSOR_HMIRROR)\n    except Exception:\n        pass\n    try:\n        sensor.set_vflip(SENSOR_VFLIP)\n    except Exception:\n        pass\n    if snapshot_chn == CAM_CHN_ID_1:\n        sensor.set_framesize(Sensor.FHD)\n        sensor.set_pixformat(Sensor.YUV420SP)\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT, chn=CAM_CHN_ID_1)\n        sensor.set_pixformat(Sensor.RGB565, chn=CAM_CHN_ID_1)\n    else:\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT)\n        sensor.set_pixformat(Sensor.RGB565)\n\n\ndef _snapshot_once(sensor, snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return sensor.snapshot(chn=CAM_CHN_ID_1)\n    return sensor.snapshot(chn=CAM_CHN_ID_0)\n\n\ndef init_camera_sensor(camera_id=None):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    try:\n        sensor = Sensor(id=camera_id)\n    except OSError as e:\n        if "already inited" not in str(e):\n            raise\n        Sensor.deinit()\n        time.sleep_ms(20)\n        sensor = Sensor(id=camera_id)\n    return sensor\n\n\ndef _start_camera_on_channel(sensor, camera_id, snapshot_chn):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    for attempt in range(START_CAMERA_RETRY_COUNT):\n        os.exitpoint()\n        try:\n            MediaManager.init()\n            sensor.run()\n            settle_ms = START_CAMERA_SETTLE_MS + attempt * START_CAMERA_SETTLE_STEP_MS\n            time.sleep_ms(settle_ms)\n            for _ in range(SENSOR_WARMUP_FRAMES):\n                os.exitpoint()\n                try:\n                    _snapshot_once(sensor, snapshot_chn)\n                    return True\n                except Exception as e:\n                    last_error = e\n                    time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n            last_error = RuntimeError(\n                "camera id {} no warmup frames on {}".format(\n                    camera_id, _snapshot_channel_name(snapshot_chn)\n                )\n            )\n        except Exception as e:\n            last_error = e\n\n        try:\n            sensor.stop()\n        except Exception:\n            pass\n        try:\n            MediaManager.deinit()\n        except Exception:\n            pass\n        try:\n            _configure_sensor_for_channel(sensor, camera_id, snapshot_chn)\n        except Exception:\n            pass\n        gc.collect()\n        time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n\n    raise last_error\n\n\ndef start_camera(sensor, camera_id=None):\n    global CURRENT_SNAPSHOT_CHN\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    channels = (CAM_CHN_ID_1,)\n    if ALLOW_CHANNEL_FALLBACK:\n        channels = (CAM_CHN_ID_1, CAM_CHN_ID_0)\n    for snapshot_chn in channels:\n        os.exitpoint()\n        try:\n            _configure_sensor_for_channel(sensor, camera_id, snapshot_chn)\n            _start_camera_on_channel(sensor, camera_id, snapshot_chn)\n            CURRENT_SNAPSHOT_CHN = snapshot_chn\n            return True\n        except Exception as e:\n            last_error = e\n            try:\n                sensor.stop()\n            except Exception:\n                pass\n            try:\n                MediaManager.deinit()\n            except Exception:\n                pass\n            gc.collect()\n            time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef snapshot_with_retry(sensor):\n    last_error = None\n    for _ in range(SNAPSHOT_RETRY_COUNT):\n        os.exitpoint()\n        try:\n            return _snapshot_once(sensor, CURRENT_SNAPSHOT_CHN)\n        except RuntimeError as e:\n            last_error = e\n            gc.collect()\n            time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef draw_text(img, x, y, text, color=(255, 255, 255), scale=1):\n    text = str(text)\n    if hasattr(img, "draw_string_advanced"):\n        img.draw_string_advanced(x, y, max(16, 16 * scale), text, color=color)\n    else:\n        img.draw_string(x, y, text, color=color, scale=scale)\n\n\ndef _pin_pull_up_value():\n    for name in ("PULL_UP", "PULLUP", "PULL_UP_ENABLE"):\n        value = getattr(Pin, name, None)\n        if value is not None:\n            return value\n    return None\n\n\ndef _map_board_pin_to_gpio(fpioa, board_pin, gpio_num):\n    if not hasattr(fpioa, "set_function"):\n        return\n    for func_name in (\n        "GPIO{}_FUNC".format(gpio_num),\n        "GPIO{}".format(gpio_num),\n        "GPIOHS{}".format(gpio_num),\n        "GPIOHS{}_FUNC".format(gpio_num),\n    ):\n        func = getattr(fpioa, func_name, None)\n        if func is not None:\n            fpioa.set_function(board_pin, func)\n            return\n\n\nclass StartButton:\n    def __init__(self, board_pin, gpio_num):\n        self.pin = None\n        self.ready = False\n        self.latched = False\n        self.last_raw_value = 1\n        self.stable_value = 1\n        self.last_change_ms = 0\n        self._init_pin(board_pin, gpio_num)\n\n    def _init_pin(self, board_pin, gpio_num):\n        try:\n            fpioa = FPIOA()\n            _map_board_pin_to_gpio(fpioa, board_pin, gpio_num)\n            pull_up = _pin_pull_up_value()\n            if pull_up is None:\n                try:\n                    self.pin = Pin(gpio_num, Pin.IN)\n                except Exception:\n                    self.pin = Pin(board_pin, Pin.IN)\n            else:\n                try:\n                    self.pin = Pin(gpio_num, Pin.IN, pull_up)\n                except Exception:\n                    self.pin = Pin(board_pin, Pin.IN, pull_up)\n            self.ready = self.pin is not None\n        except Exception as e:\n            print("[Key] start init failed:", e)\n            self.pin = None\n            self.ready = False\n\n    def poll_pressed(self):\n        if self.latched or self.pin is None:\n            return self.latched\n        now = time.ticks_ms()\n        try:\n            raw_value = self.pin.value()\n        except Exception:\n            return False\n        if raw_value != self.last_raw_value:\n            self.last_raw_value = raw_value\n            self.last_change_ms = now\n            return False\n        if time.ticks_diff(now, self.last_change_ms) < BUTTON_DEBOUNCE_MS:\n            return False\n        if raw_value != self.stable_value:\n            self.stable_value = raw_value\n            if self.stable_value == 0:\n                self.latched = True\n                return True\n        return False\n\n\ndef init_preview_display():\n    try:\n        Display.init(\n            Display.VIRT, width=FRAME_WIDTH, height=FRAME_HEIGHT, fps=100, to_ide=True\n        )\n        print("[Display] VIRT preview")\n    except Exception as e:\n        print(f"[Display] VIRT failed: {e}")\n        Display.init(Display.ST7701, to_ide=True)\n        print("[Display] ST7701 preview")\n\n\ndef restart_camera(sensor):\n    os.exitpoint()\n    print("[Sensor] restarting...")\n    try:\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n    except Exception:\n        pass\n    try:\n        MediaManager.deinit()\n    except Exception:\n        pass\n    try:\n        Sensor.deinit()\n    except Exception:\n        pass\n    gc.collect()\n    time.sleep_ms(20)\n    sensor = init_camera_sensor()\n    start_camera(sensor)\n    print("[Sensor] restart done")\n    return sensor\n\n\nclass CircleTracker:\n    def __init__(self, radius_cm=CIRCLE_RADIUS_CM, num_points=NUM_WAYPOINTS):\n        self.radius_cm = radius_cm\n        self.num_points = num_points\n        self.reset()\n\n    def get_current_target(self):\n        self.update()\n        angle = math.radians(self.current_angle_deg)\n        return {\n            "index": int(self.current_angle_deg) % 360,\n            "angle_deg": self.current_angle_deg,\n            "dx_cm": self.radius_cm * math.cos(angle),\n            "dy_cm": self.radius_cm * math.sin(angle),\n        }\n\n    def start(self):\n        self.start_ms = time.ticks_ms()\n        self.current_angle_deg = 0.0\n        self.lap_count = 0\n\n    def update(self):\n        if self.start_ms is None:\n            return\n        elapsed_ms = max(0, time.ticks_diff(time.ticks_ms(), self.start_ms))\n        total_angle_deg = (elapsed_ms * CIRCLE_SPEED_DEG_PER_SEC) / 1000.0\n        new_lap_count = int(total_angle_deg // 360.0)\n        if new_lap_count > self.lap_count:\n            self.lap_count = new_lap_count\n            print(f"[Circle] completed lap {self.lap_count}")\n        self.current_angle_deg = total_angle_deg % 360.0\n\n    def calculate_sync_error(self, laser_angle_deg):\n        target = self.get_current_target()\n        if target is None:\n            return 0.0\n\n        error = laser_angle_deg - target["angle_deg"]\n        while error > 180:\n            error -= 360\n        while error < -180:\n            error += 360\n        return error\n\n    def reset(self):\n        self.start_ms = None\n        self.current_angle_deg = 0.0\n        self.lap_count = 0\n\n\nclass PIDController:\n    def __init__(self, kp, ki, kd):\n        self.kp = kp\n        self.ki = ki\n        self.kd = kd\n        self.max_integral = 10.0\n        self.reset()\n\n    def compute(self, error, dt=0.033):\n        if dt <= 0:\n            dt = 0.001\n\n        self.integral += error * dt\n        self.integral = max(-self.max_integral, min(self.max_integral, self.integral))\n        derivative = (error - self.last_error) / dt\n        self.last_error = error\n        return self.kp * error + self.ki * self.integral + self.kd * derivative\n\n    def reset(self):\n        self.integral = 0.0\n        self.last_error = 0.0\n\n\nclass TargetDetector:\n    def __init__(self):\n        self.target_rect = None\n        self.target_center = None\n        self.target_diameter_px = 0\n        self.bullseye_center = None\n        self.laser_spot = None\n        self.target_found = False\n        self.bullseye_found = False\n        self.laser_found = False\n        self.pixel_to_cm_x = 0.0\n        self.pixel_to_cm_y = 0.0\n        self.target_plane_corners_cm = None\n        self.target_to_image_h = None\n        self.image_to_target_h = None\n        self.bullseye_plane_cm = None\n        self.frame_id = 0\n        self.target_miss_count = 0\n        self.last_target_rect = None\n        self.last_target_center = None\n        self.last_target_diameter_px = 0\n        self.last_target_corners = None\n        self.last_bullseye_center = None\n        self.bullseye_miss_count = 0\n        self.last_laser_spot = None\n        self.laser_miss_count = 0\n        self.circle_radius_px = 0.0\n        self.last_circle_radius_px = 0.0\n        self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n        self.last_detected_ring_radius_cm = 0.0\n        self.target_center_history = []\n        self.bullseye_center_history = []\n        self.laser_spot_history = []\n        self.circle_radius_history = []\n        self.ring_radius_cm_history = []\n        self.frozen_target_rect = None\n        self.frozen_target_center = None\n        self.frozen_target_diameter_px = 0\n        self.frozen_bullseye_center = None\n        self.predict_miss_count = 0\n\n    def detect_all(self, img):\n        self.frame_id += 1\n        self._detect_target(img)\n        if self.target_found:\n            self._detect_bullseye(img)\n            self._update_scale()\n            self._detect_ring_radius(img)\n            self._detect_laser(img)\n            self._refresh_prediction_anchor()\n        else:\n            if self._prediction_available() and self.predict_miss_count < PREDICT_TRACK_MAX_FRAMES:\n                self.predict_miss_count += 1\n                self.target_rect = self.frozen_target_rect\n                self.target_center = self.frozen_target_center\n                self.target_diameter_px = self.frozen_target_diameter_px\n                self.bullseye_center = self.frozen_bullseye_center\n                self.bullseye_found = self.bullseye_plane_cm is not None\n                if self.last_detected_ring_radius_cm > 0:\n                    self.detected_ring_radius_cm = self.last_detected_ring_radius_cm\n                else:\n                    self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n                self._detect_laser(img)\n            else:\n                self.target_center = None\n                self.target_diameter_px = 0\n                self.bullseye_center = None\n                self.laser_spot = None\n                self.bullseye_found = False\n                self.laser_found = False\n                self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n\n    def _clamp_rect(self, x, y, w, h):\n        x = max(0, min(FRAME_WIDTH - 1, int(x)))\n        y = max(0, min(FRAME_HEIGHT - 1, int(y)))\n        w = max(1, min(FRAME_WIDTH - x, int(w)))\n        h = max(1, min(FRAME_HEIGHT - y, int(h)))\n        return (x, y, w, h)\n\n    def _distance_sq(self, p0, p1):\n        dx = p0[0] - p1[0]\n        dy = p0[1] - p1[1]\n        return dx * dx + dy * dy\n\n    def _smooth_center(self, current, last_center, alpha, reset_px, sticky_px):\n        if last_center is None:\n            return current\n        dist_sq = self._distance_sq(current, last_center)\n        if dist_sq <= (sticky_px * sticky_px):\n            return last_center\n        if dist_sq > (reset_px * reset_px):\n            return current\n        return (\n            int(last_center[0] * (1 - alpha) + current[0] * alpha),\n            int(last_center[1] * (1 - alpha) + current[1] * alpha),\n        )\n\n    def _smooth_scalar(self, current, last_value, alpha):\n        if last_value <= 0:\n            return current\n        return last_value * (1 - alpha) + current * alpha\n\n    def _apply_motion_lead(self, current, last_center, gain, max_px):\n        if current is None or last_center is None or gain <= 0:\n            return current\n        dx = current[0] - last_center[0]\n        dy = current[1] - last_center[1]\n        lead_x = int(dx * gain)\n        lead_y = int(dy * gain)\n        if lead_x > max_px:\n            lead_x = max_px\n        elif lead_x < -max_px:\n            lead_x = -max_px\n        if lead_y > max_px:\n            lead_y = max_px\n        elif lead_y < -max_px:\n            lead_y = -max_px\n        return self._clamp_point((current[0] + lead_x, current[1] + lead_y))\n\n    def _solve_linear_system(self, matrix, values):\n        size = len(values)\n        a = []\n        for row in range(size):\n            current = []\n            for col in range(size):\n                current.append(float(matrix[row][col]))\n            current.append(float(values[row]))\n            a.append(current)\n\n        for col in range(size):\n            pivot = col\n            pivot_abs = abs(a[pivot][col])\n            for row in range(col + 1, size):\n                value_abs = abs(a[row][col])\n                if value_abs > pivot_abs:\n                    pivot = row\n                    pivot_abs = value_abs\n            if pivot_abs < 1e-6:\n                return None\n            if pivot != col:\n                tmp = a[col]\n                a[col] = a[pivot]\n                a[pivot] = tmp\n\n            pivot_value = a[col][col]\n            for idx in range(col, size + 1):\n                a[col][idx] /= pivot_value\n\n            for row in range(size):\n                if row == col:\n                    continue\n                factor = a[row][col]\n                for idx in range(col, size + 1):\n                    a[row][idx] -= factor * a[col][idx]\n\n        result = []\n        for row in range(size):\n            result.append(a[row][size])\n        return tuple(result)\n\n    def _compute_homography(self, src_points, dst_points):\n        matrix = []\n        values = []\n        for idx in range(4):\n            x = float(src_points[idx][0])\n            y = float(src_points[idx][1])\n            u = float(dst_points[idx][0])\n            v = float(dst_points[idx][1])\n            matrix.append([x, y, 1.0, 0.0, 0.0, 0.0, -u * x, -u * y])\n            values.append(u)\n            matrix.append([0.0, 0.0, 0.0, x, y, 1.0, -v * x, -v * y])\n            values.append(v)\n\n        solution = self._solve_linear_system(matrix, values)\n        if solution is None:\n            return None\n        return (\n            (solution[0], solution[1], solution[2]),\n            (solution[3], solution[4], solution[5]),\n            (solution[6], solution[7], 1.0),\n        )\n\n    def _apply_homography(self, h, x, y):\n        if h is None:\n            return None\n        denom = h[2][0] * x + h[2][1] * y + h[2][2]\n        if abs(denom) < 1e-6:\n            return None\n        out_x = (h[0][0] * x + h[0][1] * y + h[0][2]) / denom\n        out_y = (h[1][0] * x + h[1][1] * y + h[1][2]) / denom\n        return (out_x, out_y)\n\n    def _normalize_corners(self, corners):\n        sx = 0\n        sy = 0\n        points = []\n        for p in corners:\n            sx += p[0]\n            sy += p[1]\n            points.append((float(p[0]), float(p[1])))\n        center = (sx / 4, sy / 4)\n        points.sort(key=lambda p: math.atan2(p[1] - center[1], p[0] - center[0]))\n\n        top_left_idx = 0\n        best_score = points[0][0] + points[0][1]\n        for idx in range(1, 4):\n            score = points[idx][0] + points[idx][1]\n            if score < best_score:\n                best_score = score\n                top_left_idx = idx\n\n        ordered = []\n        for idx in range(4):\n            ordered.append(points[(top_left_idx + idx) % 4])\n        return ordered\n\n    def _plane_size_cm_for_corners(self, corners):\n        top = math.sqrt((corners[1][0] - corners[0][0]) ** 2 + (corners[1][1] - corners[0][1]) ** 2)\n        right = math.sqrt((corners[2][0] - corners[1][0]) ** 2 + (corners[2][1] - corners[1][1]) ** 2)\n        bottom = math.sqrt((corners[2][0] - corners[3][0]) ** 2 + (corners[2][1] - corners[3][1]) ** 2)\n        left = math.sqrt((corners[3][0] - corners[0][0]) ** 2 + (corners[3][1] - corners[0][1]) ** 2)\n        width_px = (top + bottom) * 0.5\n        height_px = (left + right) * 0.5\n        aspect = width_px / max(height_px, 1e-6)\n        normal_error = abs(aspect - TARGET_ASPECT)\n        swapped_error = abs(aspect - (1.0 / TARGET_ASPECT))\n        if swapped_error < normal_error:\n            return TARGET_HEIGHT_CM, TARGET_WIDTH_CM\n        return TARGET_WIDTH_CM, TARGET_HEIGHT_CM\n\n    def target_plane_cm_to_image(self, dx_cm, dy_cm):\n        if self.target_to_image_h is None:\n            return None\n        projected = self._apply_homography(self.target_to_image_h, dx_cm, dy_cm)\n        if projected is None:\n            return None\n        return self._clamp_point(projected)\n\n    def _point_to_target_plane_cm(self, point):\n        if self.image_to_target_h is None:\n            return None\n        projected = self._apply_homography(self.image_to_target_h, point[0], point[1])\n        if projected is None:\n            return None\n        return projected\n\n    def target_offset_cm_to_image_point(self, dx_cm, dy_cm):\n        if self.bullseye_plane_cm is None:\n            return None\n        return self.target_plane_cm_to_image(\n            self.bullseye_plane_cm[0] + dx_cm,\n            self.bullseye_plane_cm[1] + dy_cm,\n        )\n\n    def _prediction_available(self):\n        return (\n            self.frozen_target_rect is not None\n            and self.image_to_target_h is not None\n            and self.target_to_image_h is not None\n            and self.bullseye_plane_cm is not None\n        )\n\n    def _refresh_prediction_anchor(self):\n        if not self.bullseye_found:\n            return\n        if not self._prediction_available() and self.target_rect is None:\n            return\n        if self.target_rect is not None:\n            self.frozen_target_rect = self.target_rect\n        if self.target_center is not None:\n            self.frozen_target_center = self.target_center\n        if self.target_diameter_px > 0:\n            self.frozen_target_diameter_px = self.target_diameter_px\n        if self.bullseye_center is not None:\n            self.frozen_bullseye_center = self.bullseye_center\n        self.predict_miss_count = 0\n\n    def _expand_rect(self, rect, margin):\n        x, y, w, h = rect\n        return self._clamp_rect(x - margin, y - margin, w + margin * 2, h + margin * 2)\n\n    def _push_point_history(self, history, point):\n        history.append(point)\n        if len(history) > POINT_HISTORY_LEN:\n            history.pop(0)\n        return history\n\n    def _filter_point_history(self, history):\n        if not history:\n            return None\n        xs = sorted(point[0] for point in history)\n        ys = sorted(point[1] for point in history)\n        mid = len(history) // 2\n        return (xs[mid], ys[mid])\n\n    def _push_scalar_history(self, history, value):\n        history.append(value)\n        if len(history) > POINT_HISTORY_LEN:\n            history.pop(0)\n        return history\n\n    def _filter_scalar_history(self, history):\n        if not history:\n            return 0.0\n        values = sorted(history)\n        return values[len(values) // 2]\n\n    def _pixel_to_cm_avg(self):\n        values = []\n        if self.pixel_to_cm_x > 0:\n            values.append(self.pixel_to_cm_x)\n        if self.pixel_to_cm_y > 0:\n            values.append(self.pixel_to_cm_y)\n        if not values:\n            return 0.0\n        return sum(values) / len(values)\n\n    def _offset_cm_to_image_point(self, dx_cm, dy_cm):\n        if self.bullseye_center is None:\n            return None\n        pixel_to_cm = self._pixel_to_cm_avg()\n        if pixel_to_cm <= 0:\n            return None\n        cx, cy = self.bullseye_center\n        x = cx + (dx_cm / pixel_to_cm)\n        y = cy + (dy_cm / pixel_to_cm)\n        return self._clamp_point((x, y))\n\n    def _effective_ring_radius_cm(self):\n        if self.detected_ring_radius_cm > 0:\n            return self.detected_ring_radius_cm\n        return CIRCLE_RADIUS_CM\n\n    def _rect_aspect_error(self, w, h):\n        aspect = w / max(h, 1)\n        target_inv = 1.0 / TARGET_ASPECT\n        return min(abs(aspect - TARGET_ASPECT), abs(aspect - target_inv))\n\n    def _rect_center_from_corners(self, corners):\n        sx = 0\n        sy = 0\n        points = []\n        for p in corners:\n            sx += p[0]\n            sy += p[1]\n            points.append((p[0], p[1]))\n        avg_center = (sx / 4, sy / 4)\n\n        points.sort(key=lambda p: math.atan2(p[1] - avg_center[1], p[0] - avg_center[0]))\n        p0 = points[0]\n        p1 = points[1]\n        p2 = points[2]\n        p3 = points[3]\n\n        x1 = p0[0]\n        y1 = p0[1]\n        x2 = p2[0]\n        y2 = p2[1]\n        x3 = p1[0]\n        y3 = p1[1]\n        x4 = p3[0]\n        y4 = p3[1]\n\n        denom = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4)\n        if abs(denom) < 1:\n            return self._clamp_point(avg_center)\n\n        det1 = x1 * y2 - y1 * x2\n        det2 = x3 * y4 - y3 * x4\n        center_x = (det1 * (x3 - x4) - (x1 - x2) * det2) / denom\n        center_y = (det1 * (y3 - y4) - (y1 - y2) * det2) / denom\n        if center_x < -8 or center_x > (FRAME_WIDTH + 8) or center_y < -8 or center_y > (FRAME_HEIGHT + 8):\n            return self._clamp_point(avg_center)\n        return self._clamp_point((center_x, center_y))\n\n    def _clamp_point(self, point):\n        return (\n            max(0, min(FRAME_WIDTH - 1, int(point[0]))),\n            max(0, min(FRAME_HEIGHT - 1, int(point[1]))),\n        )\n\n    def _rect_size_change_ok(self, rect, last_rect):\n        if last_rect is None:\n            return True\n        _, _, w, h = rect\n        _, _, last_w, last_h = last_rect\n        if last_w <= 0 or last_h <= 0:\n            return True\n        dw = abs(w - last_w) / last_w\n        dh = abs(h - last_h) / last_h\n        return dw <= TARGET_MAX_SIZE_CHANGE_RATIO and dh <= TARGET_MAX_SIZE_CHANGE_RATIO\n\n    def _compensate_edge_rect(self, rect, last_rect):\n        if last_rect is None:\n            return rect\n        x, y, w, h = rect\n        _, _, last_w, last_h = last_rect\n        if last_w <= 0 or last_h <= 0:\n            return rect\n\n        x2 = x + w\n        y2 = y + h\n        if x <= TARGET_EDGE_MARGIN_PX and w < int(last_w * TARGET_EDGE_COMP_MIN_RATIO):\n            w = last_w\n            x2 = x + w\n        elif x2 >= (FRAME_WIDTH - TARGET_EDGE_MARGIN_PX) and w < int(last_w * TARGET_EDGE_COMP_MIN_RATIO):\n            x = max(0, x2 - last_w)\n            w = FRAME_WIDTH - x if x + last_w > FRAME_WIDTH else last_w\n\n        if y <= TARGET_EDGE_MARGIN_PX and h < int(last_h * TARGET_EDGE_COMP_MIN_RATIO):\n            h = last_h\n            y2 = y + h\n        elif y2 >= (FRAME_HEIGHT - TARGET_EDGE_MARGIN_PX) and h < int(last_h * TARGET_EDGE_COMP_MIN_RATIO):\n            y = max(0, y2 - last_h)\n            h = FRAME_HEIGHT - y if y + last_h > FRAME_HEIGHT else last_h\n\n        return self._clamp_rect(x, y, w, h)\n\n    def _rect_overlap_ratio(self, rect_a, rect_b):\n        if rect_a is None or rect_b is None:\n            return 0.0\n        ax, ay, aw, ah = rect_a\n        bx, by, bw, bh = rect_b\n        ax2 = ax + aw\n        ay2 = ay + ah\n        bx2 = bx + bw\n        by2 = by + bh\n        ix1 = max(ax, bx)\n        iy1 = max(ay, by)\n        ix2 = min(ax2, bx2)\n        iy2 = min(ay2, by2)\n        iw = ix2 - ix1\n        ih = iy2 - iy1\n        if iw <= 0 or ih <= 0:\n            return 0.0\n        inter = iw * ih\n        min_area = min(max(1, aw * ah), max(1, bw * bh))\n        return inter / min_area\n\n    def _rect_border_hit_ratio(self, rect_img, rect):\n        x, y, w, h = rect\n        if w <= 4 or h <= 4:\n            return 0.0\n        inset = max(1, min(6, min(w, h) // 12))\n        x1 = x + inset\n        y1 = y + inset\n        x2 = x + w - 1 - inset\n        y2 = y + h - 1 - inset\n        if x2 <= x1 or y2 <= y1:\n            return 0.0\n\n        hits = 0\n        total = 0\n        steps = max(4, TARGET_BORDER_SAMPLE_COUNT)\n        for idx in range(steps):\n            t = idx / max(1, steps - 1)\n            sx = int(x1 + (x2 - x1) * t)\n            sy = int(y1 + (y2 - y1) * t)\n            points = (\n                (sx, y1),\n                (sx, y2),\n                (x1, sy),\n                (x2, sy),\n            )\n            for px, py in points:\n                total += 1\n                try:\n                    if rect_img.get_pixel(px, py):\n                        hits += 1\n                except Exception:\n                    pass\n        if total <= 0:\n            return 0.0\n        return hits / total\n\n    def _select_best_rect(self, rect_img, rects, reference_center, reference_rect):\n        best = None\n        best_score = None\n        image_center = (FRAME_WIDTH // 2, FRAME_HEIGHT // 2)\n\n        for r in rects:\n            raw_rect = r.rect()\n            corners = r.corners()\n            if raw_rect is None or corners is None or len(corners) != 4:\n                continue\n            rect = self._compensate_edge_rect(raw_rect, reference_rect)\n            x, y, w, h = rect\n            if w < TARGET_MIN_W or h < TARGET_MIN_H:\n                continue\n            area = w * h\n            if area < TARGET_MIN_AREA:\n                continue\n            if not self._rect_size_change_ok(rect, reference_rect):\n                continue\n\n            center = self._rect_center_from_corners(corners)\n            border_hit_ratio = self._rect_border_hit_ratio(rect_img, rect)\n            if border_hit_ratio < TARGET_BORDER_HIT_RATIO_MIN:\n                continue\n            if reference_center is not None:\n                jump_sq = self._distance_sq(center, reference_center)\n                if jump_sq > (TARGET_RESET_DIST_PX * TARGET_RESET_DIST_PX):\n                    continue\n            if reference_rect is not None:\n                overlap_ratio = self._rect_overlap_ratio(rect, reference_rect)\n                if overlap_ratio < TARGET_MIN_OVERLAP_RATIO and (\n                    reference_center is None\n                    or self._distance_sq(center, reference_center) > (TARGET_STICKY_DIST_PX * TARGET_STICKY_DIST_PX)\n                ):\n                    continue\n            aspect_penalty = int(self._rect_aspect_error(w, h) * TARGET_ASPECT_PENALTY_SCALE)\n            if reference_center is not None:\n                distance_penalty = self._distance_sq(center, reference_center) // 10\n            else:\n                distance_penalty = self._distance_sq(center, image_center) // TARGET_INIT_CENTER_BIAS\n            edge_penalty = 0\n            if x <= 2 or y <= 2 or (x + w) >= (FRAME_WIDTH - 2) or (y + h) >= (FRAME_HEIGHT - 2):\n                edge_penalty = 3600\n            center_bias_bonus = 0\n            if self._distance_sq(center, image_center) <= (TARGET_NEAR_CENTER_PX * TARGET_NEAR_CENTER_PX):\n                center_bias_bonus = 2000\n            border_score_bonus = int(border_hit_ratio * TARGET_BORDER_SCORE_SCALE)\n\n            score = area - aspect_penalty - distance_penalty - edge_penalty + center_bias_bonus + border_score_bonus\n            if best_score is None or score > best_score:\n                best_score = score\n                best = (rect, corners, center)\n        return best\n\n    def _accept_center(self, candidate_center, last_center):\n        if candidate_center is None or last_center is None:\n            return True\n        return self._distance_sq(candidate_center, last_center) <= (TARGET_MAX_JUMP_PX * TARGET_MAX_JUMP_PX)\n\n    def _prepare_rect_image(self, img):\n        rect_img = img.to_grayscale()\n        rect_img.binary([RECT_BINARY_THRESHOLD])\n        return rect_img\n\n    def _refine_bullseye_center(self, img):\n        if not (self.target_rect and self.target_center):\n            return self.target_center\n\n        x, y, w, h = self.target_rect\n        roi_w = max(12, int(w * BULLSEYE_ROI_RATIO))\n        roi_h = max(12, int(h * BULLSEYE_ROI_RATIO))\n        cx, cy = self.target_center\n        roi_x = max(x, cx - roi_w // 2)\n        roi_y = max(y, cy - roi_h // 2)\n        roi_x2 = min(x + w, roi_x + roi_w)\n        roi_y2 = min(y + h, roi_y + roi_h)\n        roi = (\n            roi_x,\n            roi_y,\n            max(1, roi_x2 - roi_x),\n            max(1, roi_y2 - roi_y),\n        )\n\n        blobs = img.find_blobs(\n            [BLACK_THRESHOLD],\n            roi=roi,\n            pixels_threshold=3,\n            area_threshold=3,\n            merge=True,\n        ) or []\n        if not blobs:\n            return self.target_center\n\n        gate_px = max(6, int(min(w, h) * BULLSEYE_GATE_RATIO * 0.5))\n        gate_sq = gate_px * gate_px\n        weighted_x = 0.0\n        weighted_y = 0.0\n        total_weight = 0.0\n        for blob in blobs:\n            bx = blob.cx()\n            by = blob.cy()\n            dist_sq = self._distance_sq((bx, by), self.target_center)\n            if dist_sq > gate_sq:\n                continue\n            weight = max(1.0, float(blob.pixels()))\n            weighted_x += bx * weight\n            weighted_y += by * weight\n            total_weight += weight\n\n        if total_weight <= 0:\n            return self.target_center\n\n        refined = (\n            int(weighted_x / total_weight),\n            int(weighted_y / total_weight),\n        )\n        return (\n            int(self.target_center[0] * (1 - BULLSEYE_BLEND_ALPHA) + refined[0] * BULLSEYE_BLEND_ALPHA),\n            int(self.target_center[1] * (1 - BULLSEYE_BLEND_ALPHA) + refined[1] * BULLSEYE_BLEND_ALPHA),\n        )\n\n    def _detect_target(self, img):\n        if self.target_found and (self.frame_id % TARGET_DETECT_INTERVAL) != 0:\n            return\n\n        previous_rect = self.last_target_rect\n        previous_center = self.last_target_center\n        previous_diameter = self.last_target_diameter_px\n        previous_corners = self.last_target_corners\n\n        self.target_found = False\n        self.target_rect = None\n        self.target_center = None\n        self.target_diameter_px = 0\n\n        rect_img = self._prepare_rect_image(img)\n        rects = rect_img.find_rects(threshold=RECT_THRESHOLD) or []\n        chosen = self._select_best_rect(rect_img, rects, previous_center, previous_rect)\n        if chosen is not None:\n            _, _, center = chosen\n            if not self._accept_center(center, previous_center):\n                chosen = None\n\n        if chosen is None:\n            self.target_miss_count += 1\n            if previous_rect and previous_center and self.target_miss_count <= TARGET_MAX_MISS_FRAMES:\n                self.target_rect = previous_rect\n                self.target_center = previous_center\n                self.target_diameter_px = previous_diameter\n                self.last_target_corners = previous_corners\n                self.target_found = True\n            else:\n                self.last_target_rect = None\n                self.last_target_center = None\n                self.last_target_diameter_px = 0\n                self.last_target_corners = None\n                self.target_center_history = []\n                self.bullseye_center_history = []\n                self.laser_spot_history = []\n                self.circle_radius_history = []\n                self.ring_radius_cm_history = []\n                self.circle_radius_px = 0.0\n                self.last_circle_radius_px = 0.0\n                self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n                self.last_detected_ring_radius_cm = 0.0\n            return\n\n        self.target_miss_count = 0\n        rect, corners, center = chosen\n        self.target_rect = rect\n        self.target_center = self._smooth_center(\n            center,\n            previous_center,\n            TARGET_CENTER_ALPHA,\n            TARGET_RESET_DIST_PX,\n            TARGET_STICKY_DIST_PX,\n        )\n        self.target_center = self._apply_motion_lead(\n            self.target_center,\n            previous_center,\n            TARGET_LEAD_GAIN,\n            TARGET_LEAD_MAX_PX,\n        )\n        self.target_diameter_px = min(rect[2], rect[3])\n        self.target_found = True\n        self.last_target_rect = self.target_rect\n        self.last_target_corners = corners\n        self.last_target_center = self.target_center\n        self.last_target_diameter_px = self.target_diameter_px\n\n    def _detect_bullseye(self, img):\n        self.bullseye_found = False\n        self.bullseye_center = None\n        if not (self.target_found and self.target_rect and self.target_center):\n            return\n        if (\n            self.last_bullseye_center is not None\n            and (self.frame_id % BULLSEYE_DETECT_INTERVAL) != 0\n        ):\n            self.bullseye_center = self.last_bullseye_center\n            self.bullseye_found = True\n            return\n\n        refined_center = self._refine_bullseye_center(img)\n        self.bullseye_center = self._smooth_center(\n            refined_center,\n            self.last_bullseye_center,\n            BULLSEYE_CENTER_ALPHA,\n            TARGET_RESET_DIST_PX,\n            TARGET_STICKY_DIST_PX,\n        )\n        self.bullseye_center = self._apply_motion_lead(\n            self.bullseye_center,\n            self.last_bullseye_center,\n            BULLSEYE_LEAD_GAIN,\n            BULLSEYE_LEAD_MAX_PX,\n        )\n        self.last_bullseye_center = self.bullseye_center\n        self.bullseye_found = True\n        self.bullseye_miss_count = 0\n\n    def _detect_laser(self, img):\n        self.laser_found = False\n        self.laser_spot = None\n        if self.target_rect is None:\n            return\n        roi = self.target_rect\n        if not self.target_found:\n            margin = max(LASER_PREDICT_ROI_MARGIN_PX, self.target_diameter_px // 2)\n            roi = self._expand_rect(roi, margin)\n\n        blobs = img.find_blobs(\n            [VIOLET_THRESHOLD],\n            roi=roi,\n            pixels_threshold=2,\n            area_threshold=2,\n            merge=True,\n        )\n        if blobs:\n            reference = self.last_laser_spot or self.target_center\n            gate_px = max(5, self.target_diameter_px // 10)\n            gate_sq = gate_px * gate_px\n            candidate_blobs = [\n                blob\n                for blob in blobs\n                if self._distance_sq((blob.cx(), blob.cy()), reference) <= gate_sq\n            ]\n            if not candidate_blobs:\n                candidate_blobs = blobs\n            best = min(\n                candidate_blobs,\n                key=lambda b: (\n                    self._distance_sq((b.cx(), b.cy()), reference),\n                    -b.density(),\n                ),\n            )\n            raw_spot = (best.cx(), best.cy())\n            if self.last_laser_spot is None:\n                self.laser_spot = raw_spot\n            else:\n                self.laser_spot = self._smooth_center(\n                    raw_spot,\n                    self.last_laser_spot,\n                    0.9,\n                    LASER_STICKY_PX * 3,\n                    LASER_STICKY_PX,\n                )\n            self._push_point_history(self.laser_spot_history, self.laser_spot)\n            self.laser_spot = self._filter_point_history(self.laser_spot_history)\n            self.laser_found = True\n            self.last_laser_spot = self.laser_spot\n            self.laser_miss_count = 0\n        else:\n            self.laser_miss_count += 1\n            if self.last_laser_spot is not None and self.laser_miss_count <= LASER_MAX_MISS_FRAMES:\n                self.laser_spot = self.last_laser_spot\n                self._push_point_history(self.laser_spot_history, self.laser_spot)\n                self.laser_spot = self._filter_point_history(self.laser_spot_history)\n                self.laser_found = True\n            else:\n                self.laser_spot_history = []\n\n    def _detect_ring_radius(self, img):\n        if not (self.target_found and self.target_rect and self.bullseye_center):\n            self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n            return\n        if self.bullseye_plane_cm is None:\n            self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n            return\n        if (\n            self.last_detected_ring_radius_cm > 0\n            and (self.frame_id % RING_DETECT_INTERVAL) != 0\n        ):\n            self.detected_ring_radius_cm = self.last_detected_ring_radius_cm\n            return\n\n        max_blob_size = max(RING_BLOB_MIN_SIZE_PX + 1, self.target_diameter_px // RING_BLOB_MAX_SIZE_DIV)\n        black_blobs = img.find_blobs(\n            [RING_THRESHOLD],\n            roi=self.target_rect,\n            pixels_threshold=1,\n            area_threshold=1,\n            merge=False,\n        ) or []\n\n        samples = []\n        for blob in black_blobs:\n            size = max(blob.w(), blob.h())\n            if size < RING_BLOB_MIN_SIZE_PX or size > max_blob_size:\n                continue\n            plane_point = self._point_to_target_plane_cm((blob.cx(), blob.cy()))\n            if plane_point is None:\n                continue\n            dx_cm = plane_point[0] - self.bullseye_plane_cm[0]\n            dy_cm = plane_point[1] - self.bullseye_plane_cm[1]\n            radius_cm = math.sqrt(dx_cm * dx_cm + dy_cm * dy_cm)\n            if radius_cm < RING_RADIUS_MIN_CM or radius_cm > RING_RADIUS_MAX_CM:\n                continue\n            samples.append((radius_cm, max(1, min(blob.w(), blob.h()))))\n\n        if not samples:\n            if self.last_detected_ring_radius_cm > 0:\n                self.detected_ring_radius_cm = self.last_detected_ring_radius_cm\n            else:\n                self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n            return\n\n        samples.sort(key=lambda item: item[0])\n        clusters = []\n        for radius_cm, weight in samples:\n            if not clusters or abs(radius_cm - clusters[-1]["radius"]) > RING_RADIUS_CLUSTER_TOL_CM:\n                clusters.append({\n                    "radius": radius_cm,\n                    "weight_sum": float(weight),\n                    "sample_count": 1,\n                })\n            else:\n                cluster = clusters[-1]\n                total_weight = cluster["weight_sum"] + weight\n                cluster["radius"] = (\n                    cluster["radius"] * cluster["weight_sum"] + radius_cm * weight\n                ) / total_weight\n                cluster["weight_sum"] = total_weight\n                cluster["sample_count"] += 1\n\n        candidate_clusters = []\n        for cluster in clusters:\n            if (\n                cluster["sample_count"] >= RING_MIN_CLUSTER_SAMPLES\n                or cluster["weight_sum"] >= RING_MIN_CLUSTER_WEIGHT\n            ):\n                candidate_clusters.append(cluster)\n\n        if not candidate_clusters:\n            candidate_clusters = clusters\n\n        candidate_clusters.sort(key=lambda cluster: cluster["radius"])\n\n        best_cluster = None\n        target_index = RING_TARGET_INDEX_FROM_CENTER - 1\n        if 0 <= target_index < len(candidate_clusters):\n            best_cluster = candidate_clusters[target_index]\n        elif self.last_detected_ring_radius_cm > 0 and candidate_clusters:\n            best_cluster = min(\n                candidate_clusters,\n                key=lambda cluster: abs(cluster["radius"] - self.last_detected_ring_radius_cm),\n            )\n        elif candidate_clusters:\n            best_cluster = candidate_clusters[-1]\n\n        if best_cluster is None:\n            self.detected_ring_radius_cm = CIRCLE_RADIUS_CM\n            return\n\n        detected_radius = best_cluster["radius"]\n        if self.last_detected_ring_radius_cm > 0:\n            detected_radius = self._smooth_scalar(\n                detected_radius,\n                self.last_detected_ring_radius_cm,\n                CIRCLE_RADIUS_SMOOTHING_ALPHA,\n            )\n        self._push_scalar_history(self.ring_radius_cm_history, detected_radius)\n        detected_radius = self._filter_scalar_history(self.ring_radius_cm_history)\n        self.detected_ring_radius_cm = detected_radius\n        self.last_detected_ring_radius_cm = detected_radius\n\n    def _update_scale(self):\n        self.pixel_to_cm_x = 0.0\n        self.pixel_to_cm_y = 0.0\n        self.target_to_image_h = None\n        self.image_to_target_h = None\n        self.bullseye_plane_cm = None\n        if not (self.target_found and self.last_target_corners):\n            return\n\n        corners = self.last_target_corners\n        ordered_corners = self._normalize_corners(corners)\n        width_cm, height_cm = self._plane_size_cm_for_corners(ordered_corners)\n        plane_corners = (\n            (-width_cm * 0.5, height_cm * 0.5),\n            (width_cm * 0.5, height_cm * 0.5),\n            (width_cm * 0.5, -height_cm * 0.5),\n            (-width_cm * 0.5, -height_cm * 0.5),\n        )\n        self.target_plane_corners_cm = plane_corners\n        self.target_to_image_h = self._compute_homography(plane_corners, ordered_corners)\n        self.image_to_target_h = self._compute_homography(ordered_corners, plane_corners)\n        edges = []\n        for idx in range(4):\n            p0 = ordered_corners[idx]\n            p1 = ordered_corners[(idx + 1) % 4]\n            dx = p0[0] - p1[0]\n            dy = p0[1] - p1[1]\n            edges.append(math.sqrt(dx * dx + dy * dy))\n\n        width_px = (edges[0] + edges[2]) * 0.5\n        height_px = (edges[1] + edges[3]) * 0.5\n        if width_px <= 0 or height_px <= 0:\n            width_px = self.target_rect[2]\n            height_px = self.target_rect[3]\n        if width_px <= 0 or height_px <= 0:\n            return\n\n        self.pixel_to_cm_x = width_cm / width_px\n        self.pixel_to_cm_y = height_cm / height_px\n\n        radius_px = (\n            (CIRCLE_RADIUS_CM / self.pixel_to_cm_x)\n            + (CIRCLE_RADIUS_CM / self.pixel_to_cm_y)\n        ) * 0.5\n        self.circle_radius_px = self._smooth_scalar(\n            radius_px,\n            self.last_circle_radius_px,\n            CIRCLE_RADIUS_SMOOTHING_ALPHA,\n        )\n        self._push_scalar_history(\n            self.circle_radius_history,\n            self.circle_radius_px,\n        )\n        self.circle_radius_px = self._filter_scalar_history(\n            self.circle_radius_history\n        )\n        self.last_circle_radius_px = self.circle_radius_px\n        if self.bullseye_found and self.bullseye_center:\n            self.bullseye_plane_cm = self._point_to_target_plane_cm(self.bullseye_center)\n\n    def get_laser_position_cm(self):\n        if not self.bullseye_found or not self.laser_found:\n            return 0.0, 0.0, 0.0\n        if self.bullseye_plane_cm is None:\n            return 0.0, 0.0, 0.0\n        laser_plane_cm = self._point_to_target_plane_cm(self.laser_spot)\n        if laser_plane_cm is None:\n            return 0.0, 0.0, 0.0\n        dx_cm = laser_plane_cm[0] - self.bullseye_plane_cm[0]\n        dy_cm = laser_plane_cm[1] - self.bullseye_plane_cm[1]\n        angle_deg = math.degrees(math.atan2(-dy_cm, dx_cm))\n        return dx_cm, dy_cm, angle_deg\n\n    def get_error_from_target(self, target_dx_cm, target_dy_cm):\n        laser_dx, laser_dy, _ = self.get_laser_position_cm()\n        return target_dx_cm - laser_dx, target_dy_cm - laser_dy\n\n\nclass CircleModeSystem:\n    def __init__(self):\n        self.detector = TargetDetector()\n        self.tracker = CircleTracker()\n        self.uart = None\n        self.comm_started = False\n        self.start_button = StartButton(START_BUTTON_BOARD_PIN, START_BUTTON_GPIO_NUM)\n        self.frame_count = 0\n        self.gc_counter = 0\n        self.state = "IDLE"\n        self.start_align_frames = 0\n        self.last_sent_error = None\n        self.error_jump_count = 0\n\n    def _control_quality(self):\n        if not self.detector.target_found:\n            return False, "target_lost"\n        if not self.detector.bullseye_found or self.detector.bullseye_plane_cm is None:\n            return False, "bullseye_lost"\n        if not self.detector.laser_found:\n            return False, "laser_lost"\n        if self.detector.image_to_target_h is None:\n            return False, "mapping_lost"\n        return True, "ok"\n\n    def _error_distance_cm(self, error_a, error_b):\n        dx = error_a[0] - error_b[0]\n        dy = error_a[1] - error_b[1]\n        return math.sqrt(dx * dx + dy * dy)\n\n    def _filter_error_jump(self, error_x, error_y):\n        current_error = (error_x, error_y)\n        if self.last_sent_error is None:\n            self.last_sent_error = current_error\n            self.error_jump_count = 0\n            return error_x, error_y, True\n\n        if self._error_distance_cm(current_error, self.last_sent_error) <= ERROR_JUMP_MAX_CM:\n            self.last_sent_error = current_error\n            self.error_jump_count = 0\n            return error_x, error_y, True\n\n        self.error_jump_count += 1\n        if self.error_jump_count <= ERROR_JUMP_REJECT_FRAMES:\n            return self.last_sent_error[0], self.last_sent_error[1], False\n\n        self.last_sent_error = current_error\n        self.error_jump_count = 0\n        return error_x, error_y, True\n\n    def init_uart(self):\n        try:\n            fpioa = FPIOA()\n            fpioa.set_function(TX_PIN, fpioa.UART2_TXD)\n            fpioa.set_function(RX_PIN, fpioa.UART2_RXD)\n            self.uart = UART(UART_ID, baudrate=UART_BAUDRATE)\n            print(f"[UART] OK ({UART_BAUDRATE})")\n            return True\n        except Exception as e:\n            print(f"[UART] failed: {e}")\n            return False\n\n    def send_error_command(self, error_x, error_y, sync_ok):\n        if self.uart is None or not self.comm_started:\n            return\n        sync_flag = 1 if sync_ok else 0\n        self.uart.write(\n            "CIRC,{:.3f},{:.3f},{}\\n".format(error_x, error_y, sync_flag)\n        )\n\n    def send_status(self, status):\n        if self.uart and self.comm_started:\n            self.uart.write("STS,{}\\n".format(status))\n\n    def _poll_uart_commands(self):\n        commands = []\n        if (not self.uart) or (not self.comm_started):\n            return commands\n        while self.uart.any():\n            try:\n                data = self.uart.readline()\n            except Exception:\n                break\n            if not data:\n                break\n            try:\n                command = data.decode("utf-8").strip()\n            except Exception:\n                continue\n            if command:\n                commands.append(command)\n        return commands\n\n    def _start_point_error_cm(self):\n        target = self.tracker.get_current_target()\n        if (\n            target is None\n            or not self.detector.target_found\n            or not self.detector.bullseye_found\n            or not self.detector.laser_found\n        ):\n            return None\n        error_x, error_y = self.detector.get_error_from_target(\n            target["dx_cm"], target["dy_cm"]\n        )\n        return math.sqrt(error_x * error_x + error_y * error_y)\n\n    def _check_start_alignment(self):\n        start_error_cm = self._start_point_error_cm()\n        if start_error_cm is None or start_error_cm > START_ALIGN_TOL_CM:\n            self.start_align_frames = 0\n            return False\n        self.start_align_frames += 1\n        return self.start_align_frames >= START_ALIGN_HOLD_FRAMES\n\n    def _update_start_button(self):\n        if self.comm_started:\n            return\n        if self.start_button.poll_pressed():\n            self.comm_started = True\n            print("[Comm] start button pressed, UART enabled")\n            if self.state != "IDLE":\n                self.send_status(self.state)\n\n    def process_frame(self, img):\n        self.frame_count += 1\n        self.gc_counter += 1\n        self.detector.detect_all(img)\n        self._update_start_button()\n        commands = self._poll_uart_commands()\n\n        if self.state == "IDLE":\n            if self.detector.target_found and self.detector.bullseye_found:\n                self.state = "WAITING"\n                self.start_align_frames = 0\n                self.tracker.reset()\n                self.send_status("WAITING")\n                print("[State] target ready -> WAITING")\n        elif self.state == "WAITING":\n            if self._check_start_alignment():\n                self.state = "RUNNING"\n                self.tracker.reset()\n                self.tracker.start()\n                self.start_align_frames = 0\n                self.send_status("RUNNING")\n                print("[State] laser aligned with start point -> RUNNING")\n        elif self.state == "RUNNING":\n            if "STOP_CIRCLE" in commands or "STOP" in commands:\n                self.state = "WAITING"\n                self.tracker.reset()\n                self.start_align_frames = 0\n                self.last_sent_error = None\n                self.error_jump_count = 0\n                self.send_status("STOPPED")\n                print("[State] stop command -> WAITING")\n            else:\n                self._handle_running()\n\n        if DEBUG_MODE:\n            self._draw_overlay(img)\n        return img\n\n    def _handle_running(self):\n        target = self.tracker.get_current_target()\n        if target is None:\n            return\n\n        target_dx = target["dx_cm"]\n        target_dy = target["dy_cm"]\n\n        error_x, error_y = self.detector.get_error_from_target(\n            target_dx, target_dy\n        )\n        _, _, laser_angle = self.detector.get_laser_position_cm()\n        sync_error = self.tracker.calculate_sync_error(laser_angle)\n        quality_ok, _ = self._control_quality()\n        sync_ok = quality_ok and abs(sync_error) < MAX_SYNC_ERROR_DEG\n\n        if quality_ok:\n            filtered_x, filtered_y, stable_ok = self._filter_error_jump(error_x, error_y)\n            self.send_error_command(filtered_x, filtered_y, sync_ok and stable_ok)\n        else:\n            self.last_sent_error = None\n            self.error_jump_count = 0\n            self.send_error_command(0.0, 0.0, False)\n\n    def _draw_overlay(self, img):\n        if self.detector.target_found and self.detector.target_rect:\n            x, y, w, h = self.detector.target_rect\n            img.draw_rectangle(x, y, w, h, color=(0, 255, 0), thickness=2)\n        if self.detector.target_found and self.detector.target_center:\n            cx, cy = self.detector.target_center\n            img.draw_cross(cx, cy, color=(0, 255, 0), size=8)\n\n        if self.detector.target_found and self.detector.target_center:\n            if self.detector.bullseye_plane_cm is not None:\n                prev_point = None\n                sample_count = OVERLAY_RING_SAMPLE_COUNT\n                radius_cm = self.detector._effective_ring_radius_cm()\n                for idx in range(sample_count + 1):\n                    angle = 2 * math.pi * idx / sample_count\n                    sample_point = self.detector.target_offset_cm_to_image_point(\n                        radius_cm * math.cos(angle),\n                        radius_cm * math.sin(angle),\n                    )\n                    if prev_point is not None and sample_point is not None:\n                        img.draw_line(\n                            prev_point[0],\n                            prev_point[1],\n                            sample_point[0],\n                            sample_point[1],\n                            color=(0, 0, 255),\n                            thickness=2,\n                        )\n                    prev_point = sample_point\n\n                target = self.tracker.get_current_target()\n                if target:\n                    target_dx = target["dx_cm"]\n                    target_dy = target["dy_cm"]\n                    target_point = self.detector.target_offset_cm_to_image_point(target_dx, target_dy)\n                    if target_point is not None:\n                        img.draw_circle(\n                            target_point[0],\n                            target_point[1],\n                            4,\n                            color=(0, 255, 255),\n                            thickness=2,\n                        )\n\n        if self.detector.laser_found and self.detector.laser_spot:\n            lx, ly = self.detector.laser_spot\n            img.draw_circle(lx, ly, 6, color=(255, 255, 0), thickness=2)\n\n        if DEBUG_TEXT_OVERLAY:\n            state_colors = {\n                "IDLE": (128, 128, 128),\n                "WAITING": (255, 255, 0),\n                "RUNNING": (0, 255, 0),\n                "COMPLETE": (0, 255, 255),\n                "ERROR": (255, 0, 0),\n            }\n            color = state_colors.get(self.state, (255, 255, 255))\n            draw_text(img, 10, 10, f"State: {self.state}", color=color, scale=2)\n\n            if self.state == "WAITING":\n                start_error_cm = self._start_point_error_cm()\n                if start_error_cm is None:\n                    text = "Align laser to start point"\n                else:\n                    text = "Start err: {:.1f}cm".format(start_error_cm)\n                draw_text(img, 10, 40, text, color=(255, 255, 255), scale=1)\n                draw_text(\n                    img,\n                    10,\n                    60,\n                    "Hold aligned: {}/{}".format(\n                        self.start_align_frames,\n                        START_ALIGN_HOLD_FRAMES,\n                    ),\n                    color=(255, 255, 255),\n                    scale=1,\n                )\n\n            if self.state == "RUNNING":\n                target = self.tracker.get_current_target()\n                if target:\n                    target_dx = target["dx_cm"]\n                    target_dy = target["dy_cm"]\n                    draw_text(\n                        img,\n                        10,\n                        40,\n                        f"Target: {target_dx:.1f},{target_dy:.1f}",\n                        color=(255, 255, 255),\n                        scale=1,\n                    )\n                    draw_text(\n                        img,\n                        10,\n                        60,\n                        f"Lap: {self.tracker.lap_count} Angle: {target[\'angle_deg\']:.1f}",\n                        color=(255, 255, 255),\n                        scale=1,\n                    )\n        if not self.comm_started:\n            draw_text(\n                img,\n                10,\n                FRAME_HEIGHT - 20,\n                "PRESS GPIO28 TO START UART",\n                color=(255, 255, 0),\n                scale=1,\n            )\n\n\ndef main():\n    print("=" * 50)\n    print("K230 Circle Mode - laser arc tracking")\n    print("build:", BUILD_TAG)\n    print("Competition task: circle mode")\n    print("=" * 50)\n    apply_calibration()\n\n    init_preview_display()\n    sensor = init_camera_sensor()\n    start_camera(sensor)\n\n    system = CircleModeSystem()\n    system.init_uart()\n    print("system ready")\n\n    try:\n        while True:\n            os.exitpoint()\n            try:\n                img = snapshot_with_retry(sensor)\n            except RuntimeError as e:\n                print(f"[Sensor] snapshot failed, retry by restart: {e}")\n                sensor = restart_camera(sensor)\n                img = snapshot_with_retry(sensor)\n            img = system.process_frame(img)\n            Display.show_image(img)\n            time.sleep_ms(FRAME_LOOP_DELAY_MS)\n\n            if system.gc_counter >= GC_FRAME_INTERVAL:\n                gc.collect()\n                system.gc_counter = 0\n    except KeyboardInterrupt:\n        print("\\nuser interrupted")\n    except Exception as e:\n        print(f"error: {e}")\n        sys.print_exception(e)\n    finally:\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n        Display.deinit()\n        os.exitpoint(os.EXITPOINT_ENABLE_SLEEP)\n        time.sleep_ms(100)\n        MediaManager.deinit()\n        Sensor.deinit()\n        if system.uart:\n            system.uart.deinit()\n        print("system stopped")\n\n\nif __name__ == "__main__":\n    main()\n'
CALIBRATE_SOURCE = 'from media.sensor import *\nfrom media.display import *\nfrom media.media import *\nimport gc\nimport image\nimport os\nimport sys\nimport time\nfrom machine import FPIOA, Pin\n\ntry:\n    from k230_common import load_calibration, save_calibration\nexcept ImportError:\n    def load_calibration(default_red, default_black, default_violet, default_bright=None):\n        return (\n            False,\n            tuple(default_red),\n            tuple(default_black),\n            tuple(default_violet),\n            default_bright,\n        )\n\n    def save_calibration(red_threshold, black_threshold, violet_threshold, bright_threshold=None):\n        return False\n\n\nCAMERA_ID = 2\nFRAME_WIDTH = 320\nFRAME_HEIGHT = 240\nDISPLAY_WIDTH = 800\nDISPLAY_HEIGHT = 480\nSENSOR_HMIRROR = True\nSENSOR_VFLIP = True\n\nRED_THRESHOLD = (41, 100, -28, 6, -14, 14)\nBLACK_THRESHOLD = (22, 69, -23, -3, -22, 16)\nVIOLET_THRESHOLD = (92, 100, -15, 6, -9, 11)\n\nBUILD_TAG = "2026-07-14-key-calib-v2"\nCURRENT_SNAPSHOT_CHN = CAM_CHN_ID_1\nSNAPSHOT_RETRY_COUNT = 3\nSNAPSHOT_RETRY_DELAY_MS = 8\nSTART_CAMERA_RETRY_COUNT = 3\nSTART_CAMERA_RETRY_DELAY_MS = 150\nSENSOR_WARMUP_FRAMES = 10\nBUTTON_DEBOUNCE_MS = 35\nBUTTON_LONG_PRESS_MS = 700\nBUTTON_REPEAT_DELAY_MS = 320\nBUTTON_REPEAT_MS = 70\nADJUST_STEP = 2\n\n# Adjust these 4 board GPIO pins to match your wiring.\n# Wiring: GPIO pin -> button -> GND, using internal pull-up.\nBUTTON_CONFIGS = (\n    ("KEY1", 28, 28),\n    ("KEY2", 29, 29),\n    ("KEY3", 30, 30),\n    ("KEY4", 31, 31),\n)\n\nLAB_LIMITS = (\n    (0, 100),\n    (0, 100),\n    (-128, 127),\n    (-128, 127),\n    (-128, 127),\n    (-128, 127),\n)\nLAB_LABELS = ("L Min", "L Max", "A Min", "A Max", "B Min", "B Max")\nTARGET_NAMES = ("RECT", "LASER")\n\n\ndef draw_text(img, x, y, text, color=(255, 255, 255), scale=1):\n    text = str(text)\n    if hasattr(img, "draw_string_advanced"):\n        img.draw_string_advanced(x, y, max(16, 16 * scale), text, color=color)\n    else:\n        img.draw_string(x, y, text, color=color, scale=scale)\n\n\ndef _snapshot_channel_name(snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return "chn1"\n    return "chn0"\n\n\ndef _configure_sensor_for_channel(sensor, camera_id, snapshot_chn):\n    sensor.reset()\n    try:\n        sensor.set_hmirror(SENSOR_HMIRROR)\n    except Exception:\n        pass\n    try:\n        sensor.set_vflip(SENSOR_VFLIP)\n    except Exception:\n        pass\n    if snapshot_chn == CAM_CHN_ID_1:\n        sensor.set_framesize(Sensor.FHD)\n        sensor.set_pixformat(Sensor.YUV420SP)\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT, chn=CAM_CHN_ID_1)\n        sensor.set_pixformat(Sensor.RGB565, chn=CAM_CHN_ID_1)\n    else:\n        sensor.set_framesize(width=FRAME_WIDTH, height=FRAME_HEIGHT)\n        sensor.set_pixformat(Sensor.RGB565)\n\n\ndef _snapshot_once(sensor, snapshot_chn):\n    if snapshot_chn == CAM_CHN_ID_1:\n        return sensor.snapshot(chn=CAM_CHN_ID_1)\n    return sensor.snapshot(chn=CAM_CHN_ID_0)\n\n\ndef init_camera_sensor(camera_id=None):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    try:\n        sensor = Sensor(id=camera_id)\n    except OSError as e:\n        if "already inited" not in str(e):\n            raise\n        Sensor.deinit()\n        time.sleep_ms(100)\n        sensor = Sensor(id=camera_id)\n    _configure_sensor_for_channel(sensor, camera_id, CAM_CHN_ID_1)\n    return sensor\n\n\ndef _start_camera_on_channel(sensor, camera_id, snapshot_chn):\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    for _ in range(START_CAMERA_RETRY_COUNT):\n        os.exitpoint()\n        success_frames = 0\n        try:\n            MediaManager.init()\n            sensor.run()\n            time.sleep_ms(120)\n            for _ in range(SENSOR_WARMUP_FRAMES):\n                os.exitpoint()\n                try:\n                    _snapshot_once(sensor, snapshot_chn)\n                    success_frames += 1\n                except Exception as e:\n                    last_error = e\n                    time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n            if success_frames > 0:\n                return True\n            last_error = RuntimeError(\n                "camera id {} no warmup frames on {}".format(\n                    camera_id, _snapshot_channel_name(snapshot_chn)\n                )\n            )\n        except Exception as e:\n            last_error = e\n\n        try:\n            sensor.stop()\n        except Exception:\n            pass\n        try:\n            MediaManager.deinit()\n        except Exception:\n            pass\n        try:\n            _configure_sensor_for_channel(sensor, camera_id, snapshot_chn)\n        except Exception:\n            pass\n        gc.collect()\n        time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n\n    raise last_error\n\n\ndef start_camera(sensor, camera_id=None):\n    global CURRENT_SNAPSHOT_CHN\n    if camera_id is None:\n        camera_id = CAMERA_ID\n    last_error = None\n    for snapshot_chn in (CAM_CHN_ID_1, CAM_CHN_ID_0):\n        os.exitpoint()\n        try:\n            _configure_sensor_for_channel(sensor, camera_id, snapshot_chn)\n            _start_camera_on_channel(sensor, camera_id, snapshot_chn)\n            CURRENT_SNAPSHOT_CHN = snapshot_chn\n            print("[Sensor] snapshot channel:", _snapshot_channel_name(snapshot_chn))\n            return True\n        except Exception as e:\n            last_error = e\n            try:\n                sensor.stop()\n            except Exception:\n                pass\n            try:\n                MediaManager.deinit()\n            except Exception:\n                pass\n            gc.collect()\n            time.sleep_ms(START_CAMERA_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef snapshot_with_retry(sensor):\n    last_error = None\n    for _ in range(SNAPSHOT_RETRY_COUNT):\n        os.exitpoint()\n        try:\n            return _snapshot_once(sensor, CURRENT_SNAPSHOT_CHN)\n        except RuntimeError as e:\n            last_error = e\n            time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n    raise last_error\n\n\ndef init_board_display():\n    Display.init(Display.ST7701, to_ide=True)\n    print("[Display] ST7701 key preview")\n\n\ndef _pin_pull_up_value():\n    for name in ("PULL_UP", "PULLUP", "PULL_UP_ENABLE"):\n        value = getattr(Pin, name, None)\n        if value is not None:\n            return value\n    return None\n\n\ndef _map_board_pin_to_gpio(fpioa, board_pin, gpio_num):\n    if not hasattr(fpioa, "set_function"):\n        return\n    for func_name in (\n        "GPIO{}_FUNC".format(gpio_num),\n        "GPIO{}".format(gpio_num),\n        "GPIOHS{}".format(gpio_num),\n        "GPIOHS{}_FUNC".format(gpio_num),\n    ):\n        func = getattr(fpioa, func_name, None)\n        if func is not None:\n            fpioa.set_function(board_pin, func)\n            return\n\n\nclass ButtonInput:\n    def __init__(self):\n        self.buttons = {}\n        self._init_error = ""\n        self._init_buttons()\n\n    def _init_buttons(self):\n        try:\n            fpioa = FPIOA()\n            pull_up = _pin_pull_up_value()\n            for name, board_pin, gpio_num in BUTTON_CONFIGS:\n                try:\n                    _map_board_pin_to_gpio(fpioa, board_pin, gpio_num)\n                    if pull_up is None:\n                        try:\n                            pin = Pin(gpio_num, Pin.IN)\n                        except Exception:\n                            pin = Pin(board_pin, Pin.IN)\n                    else:\n                        try:\n                            pin = Pin(gpio_num, Pin.IN, pull_up)\n                        except Exception:\n                            pin = Pin(board_pin, Pin.IN, pull_up)\n                    self.buttons[name] = {\n                        "pin": pin,\n                        "pressed": False,\n                        "stable_value": 1,\n                        "last_raw_value": 1,\n                        "last_change_ms": 0,\n                        "down_ms": 0,\n                        "last_repeat_ms": 0,\n                        "long_fired": False,\n                    }\n                except Exception as e:\n                    self._init_error += "{}:{}; ".format(name, e)\n            if self.buttons:\n                print("[Keys] ready:", ",".join(self.buttons.keys()))\n            else:\n                print("[Keys] init failed")\n        except Exception as e:\n            self._init_error = str(e)\n            print("[Keys] init failed:", e)\n\n    def poll_events(self):\n        events = []\n        now = time.ticks_ms()\n        for name in self.buttons:\n            state = self.buttons[name]\n            try:\n                raw_value = state["pin"].value()\n            except Exception:\n                continue\n            if raw_value != state["last_raw_value"]:\n                state["last_raw_value"] = raw_value\n                state["last_change_ms"] = now\n                continue\n            if time.ticks_diff(now, state["last_change_ms"]) < BUTTON_DEBOUNCE_MS:\n                continue\n            if raw_value != state["stable_value"]:\n                state["stable_value"] = raw_value\n\n            is_down = (state["stable_value"] == 0)\n\n            if is_down and not state["pressed"]:\n                state["pressed"] = True\n                state["down_ms"] = now\n                state["last_repeat_ms"] = now\n                state["long_fired"] = False\n                events.append((name, "press"))\n                continue\n\n            if is_down and state["pressed"]:\n                hold_ms = time.ticks_diff(now, state["down_ms"])\n                if (not state["long_fired"]) and hold_ms >= BUTTON_LONG_PRESS_MS:\n                    state["long_fired"] = True\n                    state["last_repeat_ms"] = now\n                    events.append((name, "long"))\n                elif name in ("KEY3", "KEY4") and hold_ms >= BUTTON_REPEAT_DELAY_MS:\n                    if time.ticks_diff(now, state["last_repeat_ms"]) >= BUTTON_REPEAT_MS:\n                        state["last_repeat_ms"] = now\n                        events.append((name, "repeat"))\n                continue\n\n            if (not is_down) and state["pressed"]:\n                state["pressed"] = False\n                if not state["long_fired"]:\n                    events.append((name, "short"))\n        return events\n\n    def is_ready(self):\n        return len(self.buttons) == 4\n\n\nclass ThresholdCalibrator:\n    def __init__(self):\n        ok, red, black, violet, _ = load_calibration(\n            RED_THRESHOLD, BLACK_THRESHOLD, VIOLET_THRESHOLD\n        )\n        self.red_threshold = list(red)\n        self.black_threshold = list(black)\n        self.violet_threshold = list(violet)\n        self.initial_black_threshold = list(black)\n        self.initial_violet_threshold = list(violet)\n        self.active_target_index = 0\n        self.active_param_index = 0\n        self.status_text = "CALIB READY" if ok else "BUILT-IN THRESHOLDS"\n        self.status_expire_ms = 0\n        self.keys = ButtonInput()\n        self.last_event_text = ""\n        self.canvas = self._create_canvas()\n\n    def _create_canvas(self):\n        constructors = (\n            lambda: image.Image(DISPLAY_WIDTH, DISPLAY_HEIGHT, image.RGB565),\n            lambda: image.Image(DISPLAY_WIDTH, DISPLAY_HEIGHT),\n            lambda: image.Image(size=(DISPLAY_WIDTH, DISPLAY_HEIGHT)),\n        )\n        for make in constructors:\n            try:\n                return make()\n            except Exception:\n                pass\n        raise RuntimeError("failed to create UI canvas")\n\n    def _current_threshold(self):\n        if self.active_target_index == 0:\n            return self.black_threshold\n        return self.violet_threshold\n\n    def _current_initial_threshold(self):\n        if self.active_target_index == 0:\n            return self.initial_black_threshold\n        return self.initial_violet_threshold\n\n    def _switch_target(self):\n        self.active_target_index = 1 - self.active_target_index\n        self._set_status("TARGET " + TARGET_NAMES[self.active_target_index])\n\n    def _next_parameter(self):\n        self.active_param_index = (self.active_param_index + 1) % 6\n        self._set_status("PARAM " + LAB_LABELS[self.active_param_index])\n\n    def _normalize_threshold(self, threshold):\n        values = list(threshold)\n        for index in range(6):\n            low, high = LAB_LIMITS[index]\n            value = int(values[index])\n            if value < low:\n                value = low\n            if value > high:\n                value = high\n            values[index] = value\n\n        if values[0] > values[1]:\n            values[0] = values[1]\n        if values[2] > values[3]:\n            values[2] = values[3]\n        if values[4] > values[5]:\n            values[4] = values[5]\n        return values\n\n    def _adjust_threshold(self, index, delta):\n        threshold = self._current_threshold()\n        threshold[index] += delta\n        normalized = self._normalize_threshold(threshold)\n        for idx in range(6):\n            threshold[idx] = normalized[idx]\n        self._set_status(\n            "{} {}={}".format(\n                TARGET_NAMES[self.active_target_index],\n                LAB_LABELS[index],\n                threshold[index],\n            )\n        )\n\n    def _reset_active_threshold(self):\n        threshold = self._current_threshold()\n        initial = self._current_initial_threshold()\n        for index in range(6):\n            threshold[index] = int(initial[index])\n        self._set_status("RESET " + TARGET_NAMES[self.active_target_index])\n\n    def _save_thresholds(self):\n        ok = save_calibration(\n            tuple(self.red_threshold),\n            tuple(self.black_threshold),\n            tuple(self.violet_threshold),\n        )\n        if ok:\n            self._set_status("SAVED")\n        else:\n            self._set_status("SAVE FAILED")\n\n    def _set_status(self, text, hold_ms=1400):\n        self.status_text = text\n        self.status_expire_ms = time.ticks_add(time.ticks_ms(), hold_ms)\n\n    def _status_line(self):\n        if self.status_expire_ms and time.ticks_diff(self.status_expire_ms, time.ticks_ms()) < 0:\n            self.status_expire_ms = 0\n            self.status_text = ""\n        return self.status_text\n\n    def handle_keys(self):\n        for key_name, event_name in self.keys.poll_events():\n            self.last_event_text = "{} {}".format(key_name, event_name)\n            if key_name == "KEY1":\n                if event_name == "short":\n                    self._switch_target()\n                elif event_name == "long":\n                    self._reset_active_threshold()\n            elif key_name == "KEY2":\n                if event_name == "short":\n                    self._next_parameter()\n                elif event_name == "long":\n                    self._save_thresholds()\n            elif key_name == "KEY3":\n                if event_name in ("press", "repeat"):\n                    self._adjust_threshold(self.active_param_index, -ADJUST_STEP)\n            elif key_name == "KEY4":\n                if event_name in ("press", "repeat"):\n                    self._adjust_threshold(self.active_param_index, ADJUST_STEP)\n\n    def _fill_canvas(self):\n        try:\n            self.canvas.clear()\n            return\n        except Exception:\n            pass\n        self.canvas.draw_rectangle(0, 0, DISPLAY_WIDTH, DISPLAY_HEIGHT, color=(18, 18, 18), fill=True)\n\n    def _draw_preview(self, preview_img):\n        active_threshold = tuple(self._current_threshold())\n        try:\n            blob_img = preview_img.copy()\n        except Exception:\n            blob_img = preview_img\n\n        blobs = blob_img.find_blobs(\n            [active_threshold],\n            pixels_threshold=8,\n            area_threshold=8,\n            merge=True,\n        ) or []\n\n        try:\n            working = preview_img.copy()\n            working.binary([active_threshold])\n        except Exception:\n            working = blob_img\n\n        for blob in blobs:\n            working.draw_rectangle(blob.rect(), color=(0, 255, 0), thickness=1)\n            working.draw_cross(blob.cx(), blob.cy(), color=(255, 0, 0), size=6, thickness=1)\n\n        try:\n            self.canvas.draw_image(working, 12, 72)\n        except Exception:\n            pass\n\n        self.canvas.draw_rectangle(10, 70, FRAME_WIDTH + 4, FRAME_HEIGHT + 4, color=(255, 255, 255), thickness=2)\n        draw_text(self.canvas, 16, 42, "THRESH PREVIEW", color=(255, 255, 255), scale=1)\n        draw_text(self.canvas, 16, 348, "white = hit by threshold", color=(190, 190, 190), scale=1)\n        draw_text(self.canvas, 16, 326, "blob count: {}".format(len(blobs)), color=(180, 255, 180), scale=1)\n\n    def _draw_threshold_panel(self):\n        active_name = TARGET_NAMES[self.active_target_index]\n        threshold = self._current_threshold()\n\n        draw_text(self.canvas, 352, 66, "ACTIVE: " + active_name, color=(255, 255, 0), scale=2)\n\n        base_y = 82\n        row_h = 56\n        for index in range(6):\n            y = base_y + index * row_h\n            if index == self.active_param_index:\n                self.canvas.draw_rectangle(344, y - 2, 430, 46, color=(60, 90, 120), fill=True)\n                self.canvas.draw_rectangle(344, y - 2, 430, 46, color=(255, 255, 0), thickness=2)\n            draw_text(self.canvas, 352, y + 10, LAB_LABELS[index], color=(255, 255, 255), scale=1)\n            draw_text(self.canvas, 505, y + 10, str(threshold[index]), color=(255, 255, 0), scale=1)\n        draw_text(self.canvas, 352, 420, "KEY1 short: switch target", color=(190, 190, 190), scale=1)\n        draw_text(self.canvas, 352, 440, "KEY1 long : reset target", color=(190, 190, 190), scale=1)\n        draw_text(self.canvas, 352, 460, "KEY2 short: next param  KEY2 long: save", color=(190, 190, 190), scale=1)\n        draw_text(self.canvas, 352, 400, "KEY3/4: +/-2  hold=fast", color=(190, 190, 190), scale=1)\n\n    def _draw_status(self):\n        status = self._status_line()\n        self.canvas.draw_rectangle(10, 370, 320, 90, color=(32, 32, 32), fill=True)\n        self.canvas.draw_rectangle(10, 370, 320, 90, color=(255, 255, 255), thickness=1)\n        draw_text(self.canvas, 18, 382, "BUILD: " + BUILD_TAG, color=(180, 180, 255), scale=1)\n        draw_text(self.canvas, 18, 406, "keys ready: {}".format(self.keys.is_ready()), color=(255, 255, 255), scale=1)\n        if self.last_event_text:\n            draw_text(self.canvas, 18, 430, self.last_event_text[:36], color=(160, 255, 255), scale=1)\n        if self.keys._init_error:\n            draw_text(self.canvas, 18, 452, str(self.keys._init_error)[:36], color=(255, 128, 128), scale=1)\n        elif status:\n            draw_text(self.canvas, 18, 452, status, color=(255, 255, 0), scale=1)\n\n    def render(self, preview_img):\n        self._fill_canvas()\n        self._draw_preview(preview_img)\n        self._draw_threshold_panel()\n        self._draw_status()\n        return self.canvas\n\n\ndef main():\n    print("=" * 50)\n    print("K230 offline key calibration")\n    print("build:", BUILD_TAG)\n    print("=" * 50)\n\n    init_board_display()\n    calibrator = ThresholdCalibrator()\n    sensor = init_camera_sensor()\n    start_camera(sensor)\n\n    try:\n        while True:\n            os.exitpoint()\n            calibrator.handle_keys()\n            try:\n                img = snapshot_with_retry(sensor)\n            except RuntimeError as e:\n                print("[Sensor] snapshot failed:", e)\n                gc.collect()\n                time.sleep_ms(SNAPSHOT_RETRY_DELAY_MS)\n                continue\n            canvas = calibrator.render(img)\n            Display.show_image(canvas)\n            time.sleep_ms(20)\n    except KeyboardInterrupt:\n        print("\\n[Calib] interrupted")\n    except Exception as e:\n        print("[Calib] error:", e)\n        sys.print_exception(e)\n    finally:\n        if isinstance(sensor, Sensor):\n            sensor.stop()\n        Display.deinit()\n        os.exitpoint(os.EXITPOINT_ENABLE_SLEEP)\n        time.sleep_ms(100)\n        MediaManager.deinit()\n        Sensor.deinit()\n        print("[Calib] stopped")\n\n\nif __name__ == "__main__":\n    main()\n'

_MODULE_CACHE = {}


def _install_embedded_common():
    if not hasattr(sys, "modules"):
        sys.modules = {}
    if "k230_common" in sys.modules:
        return sys.modules["k230_common"]
    namespace = {"__name__": "k230_common"}
    exec(K230_COMMON_SOURCE, namespace)
    module = _EmbeddedModule()
    for key in namespace:
        setattr(module, key, namespace[key])
    sys.modules["k230_common"] = module
    return module


def _load_embedded_module(module_name, source):
    cached = _MODULE_CACHE.get(module_name)
    if cached is not None:
        return cached
    _install_embedded_common()
    namespace = {
        "__name__": module_name,
        "__file__": module_name + ".py",
    }
    exec(source, namespace)
    _MODULE_CACHE[module_name] = namespace
    return namespace


def _launcher_pin_pull_up_value(pin_cls):
    for name in ("PULL_UP", "PULLUP", "PULL_UP_ENABLE"):
        value = getattr(pin_cls, name, None)
        if value is not None:
            return value
    return None


def _launcher_map_board_pin_to_gpio(fpioa, board_pin, gpio_num):
    if not hasattr(fpioa, "set_function"):
        return
    for func_name in (
        "GPIO{}_FUNC".format(gpio_num),
        "GPIO{}".format(gpio_num),
        "GPIOHS{}".format(gpio_num),
        "GPIOHS{}_FUNC".format(gpio_num),
    ):
        func = getattr(fpioa, func_name, None)
        if func is not None:
            fpioa.set_function(board_pin, func)
            return


def _next_flag_value(current_flag):
    try:
        index = FLAG_SEQUENCE.index(int(current_flag))
    except Exception:
        index = -1
    return FLAG_SEQUENCE[(index + 1) % len(FLAG_SEQUENCE)]


def _select_flag_from_gpio(default_flag):
    try:
        machine = __import__("machine")
        time_mod = __import__("time")
        FPIOA = getattr(machine, "FPIOA")
        Pin = getattr(machine, "Pin")
    except Exception:
        return default_flag

    try:
        fpioa = FPIOA()
        pull_up = _launcher_pin_pull_up_value(Pin)
        buttons = []
        for key_name, board_pin, gpio_num in MODE_BUTTON_CONFIGS:
            try:
                _launcher_map_board_pin_to_gpio(fpioa, board_pin, gpio_num)
                if pull_up is None:
                    try:
                        pin = Pin(gpio_num, Pin.IN)
                    except Exception:
                        pin = Pin(board_pin, Pin.IN)
                else:
                    try:
                        pin = Pin(gpio_num, Pin.IN, pull_up)
                    except Exception:
                        pin = Pin(board_pin, Pin.IN, pull_up)
                buttons.append((key_name, pin))
            except Exception:
                pass

        if not buttons:
            return default_flag

        pressed_at_boot = False
        detect_start_ms = time_mod.ticks_ms()
        while time_mod.ticks_diff(time_mod.ticks_ms(), detect_start_ms) < MODE_BUTTON_BOOT_DETECT_MS:
            for _, pin in buttons:
                try:
                    if pin.value() == 0:
                        pressed_at_boot = True
                        break
                except Exception:
                    pass
            if pressed_at_boot:
                break
            if hasattr(time_mod, "sleep_ms"):
                time_mod.sleep_ms(MODE_BUTTON_POLL_MS)

        if not pressed_at_boot:
            return default_flag

        selected_flag = _next_flag_value(default_flag)
        print("[Launcher] MODE_BTN select start, flag {}".format(selected_flag))

        stable_value = 0
        last_raw_value = 0
        last_change_ms = time_mod.ticks_ms()
        select_deadline = time_mod.ticks_add(last_change_ms, MODE_BUTTON_SELECT_TIMEOUT_MS)
        mode_pin = buttons[0][1]

        while time_mod.ticks_diff(select_deadline, time_mod.ticks_ms()) > 0:
            try:
                raw_value = mode_pin.value()
            except Exception:
                raw_value = stable_value

            now = time_mod.ticks_ms()
            if raw_value != last_raw_value:
                last_raw_value = raw_value
                last_change_ms = now
            elif time_mod.ticks_diff(now, last_change_ms) >= MODE_BUTTON_DEBOUNCE_MS:
                if raw_value != stable_value:
                    stable_value = raw_value
                    if stable_value == 0:
                        selected_flag = _next_flag_value(selected_flag)
                        print("[Launcher] MODE_BTN -> flag {}".format(selected_flag))
                    select_deadline = time_mod.ticks_add(now, MODE_BUTTON_SELECT_TIMEOUT_MS)

            if hasattr(time_mod, "sleep_ms"):
                time_mod.sleep_ms(MODE_BUTTON_POLL_MS)

        return selected_flag
    except Exception:
        return default_flag


def _resolve_flag():
    try:
        flag = int(FLAG)
    except Exception:
        raise ValueError("FLAG must be 0, 1, 2, 3, 4, 5, or 6, got: " + str(FLAG))

    flag = _select_flag_from_gpio(flag)
    if flag == IDLE_FLAG:
        return flag, "idle", None, None
    if flag not in FLAG_MAP:
        raise ValueError("unsupported FLAG: " + str(flag))
    return flag, FLAG_MAP[flag][0], FLAG_MAP[flag][1], FLAG_MAP[flag][2]


def run():
    flag, mode, module_name, source_name = _resolve_flag()
    print("=" * 50)
    print("K230 competition launcher")
    print("flag:", flag)
    print("boot mode:", mode)
    print("source:", module_name)
    print("=" * 50)

    if flag == IDLE_FLAG:
        print("[Launcher] flag 1 selected, launcher idle")
        return

    source = globals()[source_name]
    namespace = _load_embedded_module(module_name, source)
    if "main" not in namespace:
        raise AttributeError(module_name + " has no main()")
    namespace["main"]()


if __name__ == "__main__":
    run()
